from onnx2tf.tflite_builder.tensor_buffer_builder import tflite_dtype_from_numpy


_ONNX_TYPE_TO_TFLITE_DTYPE = {
    onnx.TensorProto.FLOAT: "FLOAT32",
    onnx.TensorProto.FLOAT16: "FLOAT16",
    onnx.TensorProto.DOUBLE: "FLOAT64",
    onnx.TensorProto.INT8: "INT8",
    onnx.TensorProto.INT16: "INT16",
    onnx.TensorProto.INT32: "INT32",
    onnx.TensorProto.INT64: "INT64",
    onnx.TensorProto.UINT8: "UINT8",
    onnx.TensorProto.UINT16: "UINT16",
    onnx.TensorProto.UINT32: "UINT32",
    onnx.TensorProto.UINT64: "UINT64",
    onnx.TensorProto.BOOL: "BOOL",
    onnx.TensorProto.STRING: "STRING",
}

def _create_progress_bar(
    *,
    total: int,
    desc: str,
    enabled: bool,
):
    if not enabled or int(total) <= 0:
        return None
    try:
        from tqdm.auto import tqdm
    except Exception:
        return None
    return tqdm(
        total=int(total),
        desc=str(desc),
        dynamic_ncols=True,
    )


def _dtype_from_onnx_elem_type(elem_type: Optional[int]) -> str:
    if elem_type is None:
        return "FLOAT32"
    if elem_type not in _ONNX_TYPE_TO_TFLITE_DTYPE:
        raise NotImplementedError(f"Unsupported ONNX dtype in flatbuffer_direct: elem_type={elem_type}")
    return _ONNX_TYPE_TO_TFLITE_DTYPE[elem_type]


def _collect_constant_arrays(onnx_graph: onnx.ModelProto) -> Dict[str, np.ndarray]:
    constants: Dict[str, np.ndarray] = {}
    for ini in onnx_graph.graph.initializer:
        constants[ini.name] = np.asarray(numpy_helper.to_array(ini))
    for node in onnx_graph.graph.node:
        if str(node.op_type) != "Constant" or len(node.output) < 1:
            continue
        output_name = str(node.output[0])
        if output_name == "":
            continue
        value_attr = None
        for attr in node.attribute:
            if str(attr.name) == "value":
                value_attr = attr
                break
        if value_attr is None:
            continue
        try:
            constants[output_name] = np.asarray(numpy_helper.to_array(value_attr.t))
        except Exception:
            continue
    return constants


def _node_attr_int(node: onnx.NodeProto, attr_name: str, default: int) -> int:
    for attr in node.attribute:
        if str(attr.name) != str(attr_name):
            continue
        if attr.type == onnx.AttributeProto.INT:
            return int(attr.i)
        if attr.type == onnx.AttributeProto.INTS and len(attr.ints) > 0:
            return int(attr.ints[0])
    return int(default)


def _node_attr_ints(node: onnx.NodeProto, attr_name: str) -> List[int]:
    for attr in node.attribute:
        if str(attr.name) != str(attr_name):
            continue
        if attr.type == onnx.AttributeProto.INTS:
            return [int(v) for v in attr.ints]
        if attr.type == onnx.AttributeProto.INT:
            return [int(attr.i)]
    return []


def _infer_missing_tensor_ranks_with_axis_constraints(
    *,
    onnx_graph: onnx.ModelProto,
    shape_map: Dict[str, List[Any]],
) -> None:
    rank_map: Dict[str, int] = {}
    for name, shape in shape_map.items():
        if isinstance(shape, list) and len(shape) > 0:
            rank_map[str(name)] = max(int(rank_map.get(str(name), 0)), int(len(shape)))

    constants = _collect_constant_arrays(onnx_graph)

    def _set_min_rank(tensor_name: str, rank: int) -> bool:
        name = str(tensor_name)
        if name == "" or int(rank) <= 0:
            return False
        prev = int(rank_map.get(name, 0))
        if int(rank) > prev:
            rank_map[name] = int(rank)
            return True
        return False

    def _unify_ranks(names: List[str]) -> bool:
        normalized = [str(v) for v in names if str(v) != ""]
        if len(normalized) == 0:
            return False
        max_rank = max(int(rank_map.get(name, 0)) for name in normalized)
        if max_rank <= 0:
            return False
        changed = False
        for name in normalized:
            changed = _set_min_rank(name, max_rank) or changed
        return changed

    def _slice_axes(node: onnx.NodeProto) -> List[int]:
        if len(node.input) >= 4 and str(node.input[3]) != "":
            axes_arr = constants.get(str(node.input[3]), None)
            if axes_arr is not None:
                return [int(v) for v in np.asarray(axes_arr).reshape(-1).tolist()]
        attr_axes = _node_attr_ints(node, "axes")
        if len(attr_axes) > 0:
            return [int(v) for v in attr_axes]
        if len(node.input) >= 2 and str(node.input[1]) != "":
            starts_arr = constants.get(str(node.input[1]), None)
            if starts_arr is not None:
                starts_len = int(np.asarray(starts_arr).size)
                return [int(v) for v in range(starts_len)]
        return []

    max_iter = max(1, int(len(onnx_graph.graph.node)) * 6)
    for _ in range(max_iter):
        changed = False
        for node in onnx_graph.graph.node:
            op = str(node.op_type)
            inputs = [str(v) for v in node.input if str(v) != ""]
            outputs = [str(v) for v in node.output if str(v) != ""]
            if len(outputs) == 0:
                continue

            if op in {"QuantizeLinear", "DequantizeLinear", "Identity"}:
                if len(inputs) >= 1:
                    changed = _unify_ranks([inputs[0], outputs[0]]) or changed
                continue

            if op in {"Softmax", "LogSoftmax"}:
                if len(inputs) >= 1:
                    changed = _unify_ranks([inputs[0], outputs[0]]) or changed
                    axis = _node_attr_int(node, "axis", 1)
                    if axis >= 0:
                        min_rank = int(axis) + 1
                        changed = _set_min_rank(inputs[0], min_rank) or changed
                        changed = _set_min_rank(outputs[0], min_rank) or changed
                continue

            if op == "Slice":
                if len(inputs) >= 1:
                    changed = _unify_ranks([inputs[0], outputs[0]]) or changed
                    axes = _slice_axes(node)
                    positive_axes = [int(v) for v in axes if int(v) >= 0]
                    if len(positive_axes) > 0:
                        min_rank = max(positive_axes) + 1
                        changed = _set_min_rank(inputs[0], min_rank) or changed
                        changed = _set_min_rank(outputs[0], min_rank) or changed
                continue

            if op == "QLinearConv":
                if len(inputs) >= 1:
                    changed = _set_min_rank(inputs[0], 4) or changed
                changed = _set_min_rank(outputs[0], 4) or changed
                continue

            if op in {"Concat", "QLinearConcat"}:
                if op == "QLinearConcat":
                    data_inputs = [inputs[idx] for idx in range(2, len(inputs), 3)]
                else:
                    data_inputs = list(inputs)
                rank_linked = [str(v) for v in data_inputs if str(v) != ""] + [outputs[0]]
                changed = _unify_ranks(rank_linked) or changed
                axis = _node_attr_int(node, "axis", 1)
                if axis >= 0:
                    min_rank = int(axis) + 1
                    for tensor_name in rank_linked:
                        changed = _set_min_rank(tensor_name, min_rank) or changed
                continue

        if not changed:
            break

    for tensor_name, rank in rank_map.items():
        if int(rank) <= 0:
            continue
        current = shape_map.get(str(tensor_name), None)
        if current is None or len(current) == 0:
            shape_map[str(tensor_name)] = [-1 for _ in range(int(rank))]


def _extract_tensor_info(
    onnx_graph: onnx.ModelProto,
) -> Tuple[Dict[str, List[Any]], Dict[str, str]]:
    shape_map: Dict[str, List[Any]] = {}
    dtype_map: Dict[str, str] = {}

    def _fill_value_info(value_info):
        if not value_info.type.HasField("tensor_type"):
            return
        name = value_info.name
        tensor_type = value_info.type.tensor_type
        dims: List[Any] = []
        if tensor_type.HasField("shape"):
            for d in tensor_type.shape.dim:
                if d.HasField("dim_value") and d.dim_value >= 0:
                    dims.append(int(d.dim_value))
                else:
                    dims.append(-1)
        shape_map[name] = dims
        dtype_map[name] = _dtype_from_onnx_elem_type(tensor_type.elem_type)

    for vi in onnx_graph.graph.input:
        _fill_value_info(vi)
    for vi in onnx_graph.graph.value_info:
        _fill_value_info(vi)
    for vi in onnx_graph.graph.output:
        _fill_value_info(vi)

    for ini in onnx_graph.graph.initializer:
        arr = numpy_helper.to_array(ini)
        shape_map[ini.name] = list(arr.shape)
        dtype_map[ini.name] = tflite_dtype_from_numpy(arr.dtype)

    _infer_missing_tensor_ranks_with_axis_constraints(
        onnx_graph=onnx_graph,
        shape_map=shape_map,
    )

    return shape_map, dtype_map


def _collect_dynamic_boundary_tensor_names(onnx_graph: onnx.ModelProto) -> Dict[str, List[str]]:
    initializer_names = {str(ini.name) for ini in onnx_graph.graph.initializer}

    def _has_dynamic_dim(value_info: Any) -> bool:
        if not value_info.type.HasField("tensor_type"):
            return True
        tensor_type = value_info.type.tensor_type
        if not tensor_type.HasField("shape"):
            return True
        for d in tensor_type.shape.dim:
            if not (d.HasField("dim_value") and int(d.dim_value) >= 0):
                return True
        return False

    dynamic_inputs: List[str] = []
    for vi in onnx_graph.graph.input:
        name = str(vi.name)
        if name in initializer_names:
            continue
        if _has_dynamic_dim(vi):
            dynamic_inputs.append(name)

    dynamic_outputs: List[str] = []
    for vi in onnx_graph.graph.output:
        name = str(vi.name)
        if _has_dynamic_dim(vi):
            dynamic_outputs.append(name)

    return {
        "inputs": dynamic_inputs,
        "outputs": dynamic_outputs,
    }


def _build_onnx_boundary_shape_signature_map(
    *,
    onnx_graph: onnx.ModelProto,
    shape_map: Dict[str, List[Any]],
) -> Dict[str, List[int]]:
    signature_map: Dict[str, List[int]] = {}
    initializer_names = {str(ini.name) for ini in onnx_graph.graph.initializer}
    for value_info in list(onnx_graph.graph.input) + list(onnx_graph.graph.output):
        name = str(value_info.name)
        if name == "" or name in initializer_names:
            continue
        raw_shape = shape_map.get(name, None)
        _, signature = normalize_onnx_shape(raw_shape)
        signature_map[name] = [int(v) for v in list(signature)]
    return signature_map


def _align_boundary_signature_to_current_shape(
    *,
    boundary_signature: Optional[List[int]],
    current_shape: Optional[List[int]],
) -> Optional[List[int]]:
    if boundary_signature is None or current_shape is None:
        return None
    signature = [int(v) for v in list(boundary_signature)]
    shape = [int(v) for v in list(current_shape)]
    if len(signature) == 0 or len(signature) != len(shape):
        return None

    # Fast-path when no layout permutation is observed.
    # Keep boundary axis contracts (including singleton dims) whenever the
    # current static shape is compatible on the same axes.
    static_axes = [int(i) for i, v in enumerate(signature) if int(v) >= 0]
    if len(static_axes) > 0 and all(int(signature[i]) == int(shape[i]) for i in static_axes):
        return [int(v) for v in list(signature)]

    aligned = [-1 for _ in range(len(signature))]
    used_axes: set[int] = set()
    static_values = sorted({int(v) for v in signature if int(v) > 1})
    for value in static_values:
        needed = int(sum(1 for v in signature if int(v) == value))
        if needed <= 0:
            continue
        candidate_axes = [int(i) for i, dim in enumerate(shape) if int(dim) == value and int(i) not in used_axes]
        if len(candidate_axes) < needed:
            continue
        for axis in candidate_axes[:needed]:
            aligned[int(axis)] = int(value)
            used_axes.add(int(axis))
    return [int(v) for v in aligned]


def _graph_has_missing_rank_info(onnx_graph: onnx.ModelProto) -> bool:
    value_infos = (
        list(onnx_graph.graph.input)
        + list(onnx_graph.graph.value_info)
        + list(onnx_graph.graph.output)
    )
    for vi in value_infos:
        if not vi.type.HasField("tensor_type"):
            continue
        if not vi.type.tensor_type.HasField("shape"):
            return True
    return False


def _infer_shapes_with_fallback(onnx_graph: onnx.ModelProto) -> onnx.ModelProto:
    inferred_graph = onnx_graph
    try:
        inferred_graph = onnx.shape_inference.infer_shapes(inferred_graph)
    except Exception:
        pass

    if not _graph_has_missing_rank_info(inferred_graph):
        return inferred_graph

    try:
        from onnxruntime.tools.symbolic_shape_infer import SymbolicShapeInference
    except Exception:
        return inferred_graph

    try:
        return SymbolicShapeInference.infer_shapes(
            inferred_graph,
            auto_merge=True,
            guess_output_rank=True,
        )
    except TypeError:
        try:
            return SymbolicShapeInference.infer_shapes(inferred_graph)
        except Exception:
            return inferred_graph
    except Exception:
        return inferred_graph


class LoweringContext:
    def __init__(
        self,
        model_ir: ModelIR,
        shape_map: Dict[str, List[Any]],
        dtype_map: Dict[str, str],
        constants: Dict[str, np.ndarray],
        onnx_model: Optional[Any] = None,
        allow_custom_ops: bool = False,
        custom_op_allowlist: Optional[List[str]] = None,
        disable_group_convolution: bool = False,
        tensor_consumer_count: Optional[Dict[str, int]] = None,
        graph_output_names: Optional[List[str]] = None,
        output_nms_with_argmax: bool = False,
        switch_nms_version: str = "v4",
        number_of_dimensions_after_flextranspose_compression: int = 6,
        number_of_dimensions_after_flexstridedslice_compression: int = 5,
    ):
        self.model_ir = model_ir
        self.shape_map = shape_map
        self.dtype_map = dtype_map
        self.constants = constants
        self.onnx_model = onnx_model
        self.allow_custom_ops = bool(allow_custom_ops)
        self.custom_op_allowlist = (
            list(custom_op_allowlist) if custom_op_allowlist is not None else None
        )
        self.disable_group_convolution = bool(disable_group_convolution)
        self.tensor_consumer_count = (
            dict(tensor_consumer_count)
            if isinstance(tensor_consumer_count, dict)
            else {}
        )
        self.graph_output_names = set(graph_output_names) if graph_output_names is not None else set()
        self.output_nms_with_argmax = bool(output_nms_with_argmax)
        # TFLite TRANSPOSE kernel supports rank <= 6.
        # Keep user intent (>=2) while clamping to runtime-safe upper bound.
        self.number_of_dimensions_after_flextranspose_compression = int(
            max(2, min(6, int(number_of_dimensions_after_flextranspose_compression)))
        )
        # TFLite SLICE kernel supports rank <= 5.
        # Keep user intent (>=1) while clamping to runtime-safe upper bound.
        self.number_of_dimensions_after_flexstridedslice_compression = int(
            max(1, min(5, int(number_of_dimensions_after_flexstridedslice_compression)))
        )
        nms_version = str(switch_nms_version).strip().lower()
        if nms_version not in {"v4", "v5"}:
            raise ValueError(
                "switch_nms_version must be 'v4' or 'v5'. "
                f"got: {switch_nms_version}"
            )
        self.switch_nms_version = nms_version
        self._serial = 0

    def _next_name(self, base: str) -> str:
        self._serial += 1
        return f"{base}_{self._serial}"

    def get_tensor_shape(self, name: str) -> List[int]:
        if name in self.model_ir.tensors:
            return list(self.model_ir.tensors[name].shape)
        shape = self.shape_map.get(name, None)
        norm_shape, _ = normalize_onnx_shape(shape)
        return norm_shape

    def get_tensor_dtype(self, name: str) -> str:
        if name in self.model_ir.tensors:
            return self.model_ir.tensors[name].dtype
        return self.dtype_map.get(name, "FLOAT32")

    def get_constant_array(self, name: str) -> Optional[np.ndarray]:
        if name in self.constants:
            return self.constants[name]
        t = self.model_ir.tensors.get(name, None)
        if t is not None and isinstance(t.data, np.ndarray):
            return t.data
        return None

    def ensure_tensor(self, name: str, dtype: Optional[str] = None, shape: Optional[List[int]] = None) -> str:
        if name == "":
            raise ValueError("Tensor name must not be empty in flatbuffer_direct lowering.")
        if name in self.model_ir.tensors:
            return name
        if dtype is None:
            dtype = self.dtype_map.get(name, "FLOAT32")
        if shape is None:
            shape = self.shape_map.get(name, None)
        shape, signature = normalize_onnx_shape(shape)
        self.model_ir.tensors[name] = TensorIR(
            name=name,
            dtype=dtype,
            shape=list(shape),
            shape_signature=list(signature),
            data=self.constants.get(name, None),
        )
        return name

    def add_const_tensor(self, base_name: str, data: np.ndarray) -> str:
        name = base_name
        if name in self.model_ir.tensors:
            name = self._next_name(base_name)
        data = np.asarray(data)
        dtype = tflite_dtype_from_numpy(data.dtype)
        shape, signature = normalize_onnx_shape(list(data.shape))
        self.model_ir.tensors[name] = TensorIR(
            name=name,
            dtype=dtype,
            shape=shape,
            shape_signature=signature,
            data=data,
        )
        self.constants[name] = data
        return name

    def add_intermediate_tensor(self, base_name: str, dtype: str, shape: List[int]) -> str:
        if base_name == "":
            raise ValueError("Tensor name must not be empty in flatbuffer_direct lowering.")
        name = base_name
        if name in self.model_ir.tensors:
            name = self._next_name(base_name)
        norm_shape, signature = normalize_onnx_shape(shape)
        self.model_ir.tensors[name] = TensorIR(
            name=name,
            dtype=dtype,
            shape=norm_shape,
            shape_signature=signature,
            data=None,
        )
        return name

    def add_operator(self, op: OperatorIR) -> None:
        self.model_ir.operators.append(op)


class _NodeWrap:
    def __init__(
        self,
        n: onnx.NodeProto,
        input_name_remap: Optional[Dict[str, str]] = None,
    ):
        self.name = n.name if n.name else n.op_type
        self.op = n.op_type
        self.attrs = {}
        for a in n.attribute:
            if a.type == onnx.AttributeProto.INT:
                self.attrs[a.name] = int(a.i)
            elif a.type == onnx.AttributeProto.FLOAT:
                self.attrs[a.name] = float(a.f)
            elif a.type == onnx.AttributeProto.INTS:
                self.attrs[a.name] = [int(v) for v in a.ints]
            elif a.type == onnx.AttributeProto.FLOATS:
                self.attrs[a.name] = [float(v) for v in a.floats]
            elif a.type == onnx.AttributeProto.STRING:
                self.attrs[a.name] = a.s.decode("utf-8")
            elif a.type == onnx.AttributeProto.STRINGS:
                self.attrs[a.name] = [v.decode("utf-8") for v in a.strings]
            elif a.type == onnx.AttributeProto.GRAPH:
                self.attrs[a.name] = a.g
            elif a.type == onnx.AttributeProto.GRAPHS:
                self.attrs[a.name] = [g for g in a.graphs]
            else:
                pass
        remap = input_name_remap if isinstance(input_name_remap, dict) else {}
        self.inputs = [
            type("In", (), {"name": remap.get(i, i)})
            for i in n.input
            if i != ""
        ]
        self.outputs = [type("Out", (), {"name": o}) for o in n.output if o != ""]


def _build_tensor_consumer_map(model_ir: ModelIR) -> Dict[str, List[int]]:
    consumers: Dict[str, List[int]] = {}
    for op_idx, op in enumerate(model_ir.operators):
        for input_name in op.inputs:
            if input_name not in consumers:
                consumers[input_name] = []
            consumers[input_name].append(op_idx)
    return consumers


def _read_transpose_perm(model_ir: ModelIR, op: OperatorIR) -> Optional[List[int]]:
    if str(op.op_type) != "TRANSPOSE":
        return None
    if len(op.inputs) < 2:
        return None
    perm_tensor_name = op.inputs[1]
    perm_tensor = model_ir.tensors.get(perm_tensor_name, None)
    if perm_tensor is None or perm_tensor.data is None:
        return None
    perm = np.asarray(perm_tensor.data).reshape(-1)
    if perm.size == 0:
        return None
    return [int(v) for v in perm.tolist()]


def _is_identity_perm(perm: List[int]) -> bool:
    return perm == [int(i) for i in range(len(perm))]


def _is_inverse_perm(perm_a: List[int], perm_b: List[int]) -> bool:
    if len(perm_a) != len(perm_b):
        return False
    rank = len(perm_a)
    if sorted(perm_a) != [int(i) for i in range(rank)]:
        return False
    if sorted(perm_b) != [int(i) for i in range(rank)]:
        return False
    for idx, value in enumerate(perm_a):
        if perm_b[value] != idx:
            return False
    return True


def _invert_perm(perm: List[int]) -> Optional[List[int]]:
    rank = len(perm)
    if sorted(perm) != [int(i) for i in range(rank)]:
        return None
    inv = [0 for _ in range(rank)]
    for idx, value in enumerate(perm):
        inv[int(value)] = int(idx)
    return inv


def _append_tensor_lineage_event(
    *,
    model_ir: ModelIR,
    event: Dict[str, Any],
) -> None:
    if "tensor_lineage_events" not in model_ir.metadata:
        model_ir.metadata["tensor_lineage_events"] = []
    events = model_ir.metadata["tensor_lineage_events"]
    if not isinstance(events, list):
        events = []
        model_ir.metadata["tensor_lineage_events"] = events
    normalized_event = dict(event)
    normalized_event["event_index"] = int(len(events))
    events.append(normalized_event)


def _replace_tensor_inputs(model_ir: ModelIR, src_name: str, dst_name: str) -> None:
    if str(src_name) != str(dst_name):
        _append_tensor_lineage_event(
            model_ir=model_ir,
            event={
                "kind": "replace_input",
                "src_name": str(src_name),
                "dst_name": str(dst_name),
            },
        )
    for op in model_ir.operators:
        if len(op.inputs) > 0:
            op.inputs = [dst_name if input_name == src_name else input_name for input_name in op.inputs]


def _set_operator_inputs(
    *,
    model_ir: ModelIR,
    op: OperatorIR,
    new_inputs: List[str],
) -> None:
    old_inputs = [str(v) for v in list(op.inputs)]
    normalized_new_inputs = [str(v) for v in list(new_inputs)]
    pair_count = int(min(len(old_inputs), len(normalized_new_inputs)))
    for index in range(pair_count):
        old_name = str(old_inputs[index])
        new_name = str(normalized_new_inputs[index])
        if old_name == new_name:
            continue
        _append_tensor_lineage_event(
            model_ir=model_ir,
            event={
                "kind": "replace_input",
                "src_name": old_name,
                "dst_name": new_name,
                "source": "set_operator_inputs",
            },
        )
    op.inputs = normalized_new_inputs


def _set_operator_outputs(
    *,
    model_ir: ModelIR,
    op: OperatorIR,
    new_outputs: List[str],
) -> None:
    old_outputs = [str(v) for v in list(op.outputs)]
    normalized_new_outputs = [str(v) for v in list(new_outputs)]
    pair_count = int(min(len(old_outputs), len(normalized_new_outputs)))
    for index in range(pair_count):
        old_name = str(old_outputs[index])
        new_name = str(normalized_new_outputs[index])
        if old_name == new_name:
            continue
        _append_tensor_lineage_event(
            model_ir=model_ir,
            event={
                "kind": "rename_tensor",
                "old_name": old_name,
                "new_name": new_name,
                "source": "set_operator_outputs",
            },
        )
    op.outputs = normalized_new_outputs


def _replace_operator_input_at(
    *,
    model_ir: ModelIR,
    op: OperatorIR,
    input_index: int,
    new_input_name: str,
) -> None:
    if int(input_index) < 0 or int(input_index) >= len(op.inputs):
        return
    old_name = str(op.inputs[int(input_index)])
    new_name = str(new_input_name)
    if old_name != new_name:
        _append_tensor_lineage_event(
            model_ir=model_ir,
            event={
                "kind": "replace_input",
                "src_name": old_name,
                "dst_name": new_name,
                "source": "replace_operator_input_at",
            },
        )
    op.inputs[int(input_index)] = new_name


def _prune_unused_tensors(model_ir: ModelIR) -> None:
    used_tensor_names = set(model_ir.inputs + model_ir.outputs)
    for op in model_ir.operators:
        used_tensor_names.update(op.inputs)
        used_tensor_names.update(op.outputs)
    unused_tensor_names = [name for name in model_ir.tensors.keys() if name not in used_tensor_names]
    if len(unused_tensor_names) > 0:
        _append_tensor_lineage_event(
            model_ir=model_ir,
            event={
                "kind": "prune_unused_tensors",
                "removed_names": [str(v) for v in unused_tensor_names],
            },
        )
    for name in unused_tensor_names:
        del model_ir.tensors[name]


def _prune_dead_operators(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove operators that do not contribute to graph outputs.

    This pass performs a reverse liveness walk from model outputs and keeps only
    operators whose outputs are required by downstream live operators or graph outputs.
    """
    if len(model_ir.operators) == 0:
        return {"removed_dead_operators": 0}

    live_tensors = set(model_ir.outputs)
    keep_flags = [False for _ in model_ir.operators]

    for op_idx in range(len(model_ir.operators) - 1, -1, -1):
        op = model_ir.operators[op_idx]
        outputs = list(op.outputs)
        outputs_live = any(out_name in live_tensors for out_name in outputs)

        # Some kernels (e.g. UNIDIRECTIONAL_SEQUENCE_RNN) mutate variable input
        # tensors in-place. Keep such ops when a live tensor depends on that
        # variable state even if the op's explicit outputs are currently dead.
        mutates_live_variable_input = False
        if not outputs_live:
            for input_name in op.inputs:
                if input_name not in live_tensors:
                    continue
                input_tensor = model_ir.tensors.get(str(input_name), None)
                if input_tensor is not None and bool(input_tensor.is_variable):
                    mutates_live_variable_input = True
                    break

        if outputs_live or mutates_live_variable_input:
            keep_flags[op_idx] = True
            for input_name in op.inputs:
                live_tensors.add(input_name)

    removed = int(sum(1 for keep in keep_flags if not keep))
    if removed == 0:
        return {"removed_dead_operators": 0}

    model_ir.operators = [
        op for idx, op in enumerate(model_ir.operators) if keep_flags[idx]
    ]
    _prune_unused_tensors(model_ir)
    return {"removed_dead_operators": removed}


def _find_unbound_nonconstant_operator_inputs(model_ir: ModelIR) -> List[Dict[str, Any]]:
    """
    Detect operator inputs that are neither:
    - produced by another operator,
    - model inputs, nor
    - constant tensors with embedded data.

    Such tensors become unexpected runtime-fed inputs in TFLite and can trigger
    errors like "Input tensor N lacks data".
    """
    producers = _build_tensor_producer_map(model_ir)
    model_inputs = {str(v) for v in list(model_ir.inputs)}
    issues: List[Dict[str, Any]] = []

    for op_index, op in enumerate(model_ir.operators):
        for input_index, input_name_raw in enumerate(op.inputs):
            input_name = str(input_name_raw)
            if input_name == "":
                continue
            if input_name in model_inputs:
                continue
            if input_name in producers:
                continue
            tensor = model_ir.tensors.get(input_name, None)
            if tensor is not None and tensor.data is not None:
                continue
            issues.append(
                {
                    "op_index": int(op_index),
                    "op_type": str(op.op_type),
                    "input_index": int(input_index),
                    "tensor_name": str(input_name),
                }
            )
    return issues


def _repair_unbound_nonconstant_operator_inputs_with_layout_transpose(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Repair a strict subset of unbound dynamic inputs by inserting a layout transpose.

    Current target (conservative):
    - Unbound tensor `t` is rank-4 NCHW and used as input[0] of RESHAPE.
    - There exists an earlier produced rank-4 NHWC tensor `s` with
      shape [N,H,W,C] where `t` has shape [N,C,H,W].
    - Insert `TRANSPOSE(s, [0,3,1,2]) -> t` just before the consumer.
    """
    repaired = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        serial = 1
        while name in model_ir.tensors:
            name = f"{base}_{serial}"
            serial += 1
        return name

    while True:
        issues = _find_unbound_nonconstant_operator_inputs(model_ir)
        if len(issues) <= 0:
            break

        producers = _build_tensor_producer_map(model_ir)
        changed = False

        for issue in issues:
            op_index = int(issue.get("op_index", -1))
            input_index = int(issue.get("input_index", -1))
            tensor_name = str(issue.get("tensor_name", ""))
            if op_index < 0 or op_index >= len(model_ir.operators):
                continue
            if input_index != 0:
                continue

            consumer_op = model_ir.operators[int(op_index)]
            if str(consumer_op.op_type) != "RESHAPE":
                continue
            if input_index >= len(consumer_op.inputs) or str(consumer_op.inputs[input_index]) != tensor_name:
                continue

            orphan_tensor = model_ir.tensors.get(tensor_name, None)
            if orphan_tensor is None or not _is_fully_known_positive_shape(orphan_tensor.shape):
                continue
            orphan_shape = [int(v) for v in list(orphan_tensor.shape)]
            if len(orphan_shape) != 4:
                continue

            n, c, h, w = [int(v) for v in list(orphan_shape)]
            expected_source_shape = [int(n), int(h), int(w), int(c)]

            best_source_name: Optional[str] = None
            best_source_op_index = -1
            for produced_name, source_op_index in producers.items():
                source_idx = int(source_op_index)
                if source_idx >= int(op_index):
                    continue
                source_tensor = model_ir.tensors.get(str(produced_name), None)
                if source_tensor is None:
                    continue
                if source_tensor.data is not None:
                    continue
                if not _is_fully_known_positive_shape(source_tensor.shape):
                    continue
                source_shape = [int(v) for v in list(source_tensor.shape)]
                if source_shape != expected_source_shape:
                    continue
                if source_idx > int(best_source_op_index):
                    best_source_op_index = int(source_idx)
                    best_source_name = str(produced_name)

            if best_source_name is None:
                continue

            perm_name = _unique_tensor_name(f"{tensor_name}_repair_perm")
            model_ir.tensors[perm_name] = TensorIR(
                name=perm_name,
                dtype="INT32",
                shape=[4],
                shape_signature=[4],
                data=np.asarray([0, 3, 1, 2], dtype=np.int32),
                is_variable=False,
            )

            model_ir.operators.insert(
                int(op_index),
                OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[str(best_source_name), str(perm_name)],
                    outputs=[str(tensor_name)],
                    options={},
                ),
            )

            repaired += 1
            changed = True
            break

        if not changed:
            break

    if repaired > 0:
        _reconcile_static_tensor_shapes(model_ir)
    return {"repaired_unbound_nonconstant_inputs_with_layout_transpose": int(repaired)}


def _count_ops_by_type(model_ir: ModelIR, op_type: str) -> int:
    target = str(op_type)
    return int(sum(1 for op in model_ir.operators if str(op.op_type) == target))


def _apply_safe_transpose_reduction_lite(model_ir: ModelIR) -> Dict[str, int]:
    """
    Run a conservative transpose-reduction bundle for fallback/non-aggressive paths.

    Safety contract:
    - Apply only a curated set of historically safe transpose/layout passes.
    - Roll back all changes if unbound runtime inputs are introduced.
    """
    before_transpose = _count_ops_by_type(model_ir, "TRANSPOSE")
    if int(before_transpose) <= 0:
        return {
            "safe_transpose_reduction_lite_applied": 0,
            "safe_transpose_reduction_lite_reduced": 0,
            "safe_transpose_reduction_lite_unbound_after": 0,
        }

    snapshot = copy.deepcopy(model_ir)
    pass_sequence = [
        _optimize_transpose_quant_dequant_bridges,
        _optimize_duplicate_transpose_fanout,
        _optimize_singleton_channel_layout_transpose_to_reshape,
        _optimize_transpose_unary_fanout_inverse_post_bridges,
        _optimize_transpose_unary_passthrough_chains,
        _optimize_transpose_elementwise_concat_conv_nhwc_groups,
        _optimize_transpose_input_chains_pre_concat_to_single_post_adapter,
        _optimize_transpose_pre_add_nhwc_chains,
        _optimize_transpose_se_fc_mul_prepost_nhwc_chains,
        _optimize_transpose_elementwise_roundtrip_nhwc_nchw_fanout_chains,
        _optimize_transposeconv_output_nhwc_passthrough_chains,
    ]

    applied = 0
    for optimize_pass in pass_sequence:
        optimize_pass(model_ir)
        applied += 1

    _prune_dead_operators(model_ir)
    _reconcile_static_tensor_shapes(model_ir)

    unbound_after = _find_unbound_nonconstant_operator_inputs(model_ir)
    if len(unbound_after) > 0:
        model_ir.tensors = snapshot.tensors
        model_ir.operators = snapshot.operators
        model_ir.inputs = snapshot.inputs
        model_ir.outputs = snapshot.outputs
        model_ir.subgraphs = snapshot.subgraphs
        model_ir.metadata = snapshot.metadata
        return {
            "safe_transpose_reduction_lite_applied": 0,
            "safe_transpose_reduction_lite_reduced": 0,
            "safe_transpose_reduction_lite_unbound_after": int(len(unbound_after)),
        }

    after_transpose = _count_ops_by_type(model_ir, "TRANSPOSE")
    reduced = int(before_transpose - after_transpose)
    if reduced <= 0:
        model_ir.tensors = snapshot.tensors
        model_ir.operators = snapshot.operators
        model_ir.inputs = snapshot.inputs
        model_ir.outputs = snapshot.outputs
        model_ir.subgraphs = snapshot.subgraphs
        model_ir.metadata = snapshot.metadata
        return {
            "safe_transpose_reduction_lite_applied": 0,
            "safe_transpose_reduction_lite_reduced": 0,
            "safe_transpose_reduction_lite_unbound_after": 0,
        }

    return {
        "safe_transpose_reduction_lite_applied": int(applied),
        "safe_transpose_reduction_lite_reduced": int(reduced),
        "safe_transpose_reduction_lite_unbound_after": 0,
    }


def _build_tensor_producer_map(model_ir: ModelIR) -> Dict[str, int]:
    producers: Dict[str, int] = {}
    for op_idx, op in enumerate(model_ir.operators):
        for output_name in op.outputs:
            producers[output_name] = op_idx
    return producers


def _topologically_sort_operators(model_ir: ModelIR) -> Dict[str, int]:
    """
    Reorder operators so every producer appears before its consumers.

    This is a safety net for late graph-rewrite passes that may rewrite tensor
    names without physically moving operators.
    """
    op_count = len(model_ir.operators)
    if op_count <= 1:
        return {"reordered_operators": 0, "cycle_detected": 0}

    producers = _build_tensor_producer_map(model_ir)
    dependencies: List[set[int]] = [set() for _ in range(op_count)]
    dependents: List[set[int]] = [set() for _ in range(op_count)]

    for consumer_idx, op in enumerate(model_ir.operators):
        for input_name in op.inputs:
            producer_idx = producers.get(str(input_name), None)
            if producer_idx is None or int(producer_idx) == int(consumer_idx):
                continue
            if int(producer_idx) in dependencies[int(consumer_idx)]:
                continue
            dependencies[int(consumer_idx)].add(int(producer_idx))
            dependents[int(producer_idx)].add(int(consumer_idx))

    indegree = [int(len(v)) for v in dependencies]
    ready = [int(idx) for idx, deg in enumerate(indegree) if int(deg) == 0]
    ready.sort()
    sorted_indices: List[int] = []

    while len(ready) > 0:
        current = int(ready.pop(0))
        sorted_indices.append(current)
        for dependent_idx in sorted(list(dependents[current])):
            indegree[int(dependent_idx)] -= 1
            if int(indegree[int(dependent_idx)]) == 0:
                ready.append(int(dependent_idx))
        ready.sort()

    if len(sorted_indices) != op_count:
        return {"reordered_operators": 0, "cycle_detected": 1}

    if sorted_indices == [int(v) for v in range(op_count)]:
        return {"reordered_operators": 0, "cycle_detected": 0}

    original_ops = list(model_ir.operators)
    model_ir.operators = [original_ops[int(idx)] for idx in sorted_indices]
    return {
        "reordered_operators": int(
            sum(1 for new_idx, old_idx in enumerate(sorted_indices) if int(new_idx) != int(old_idx))
        ),
        "cycle_detected": 0,
    }


def _rename_tensor_globally(
    model_ir: ModelIR,
    old_name: str,
    new_name: str,
) -> None:
    if old_name == new_name:
        return

    for op in model_ir.operators:
        if len(op.inputs) > 0:
            op.inputs = [new_name if input_name == old_name else input_name for input_name in op.inputs]
        if len(op.outputs) > 0:
            op.outputs = [new_name if output_name == old_name else output_name for output_name in op.outputs]

    if len(model_ir.inputs) > 0:
        model_ir.inputs = [new_name if input_name == old_name else input_name for input_name in model_ir.inputs]
    if len(model_ir.outputs) > 0:
        model_ir.outputs = [new_name if output_name == old_name else output_name for output_name in model_ir.outputs]

    old_tensor = model_ir.tensors.get(old_name, None)
    if old_tensor is None:
        if new_name in model_ir.tensors:
            del model_ir.tensors[new_name]
        return
    old_tensor.name = new_name
    if new_name in model_ir.tensors and new_name != old_name:
        del model_ir.tensors[new_name]
    del model_ir.tensors[old_name]
    model_ir.tensors[new_name] = old_tensor
    _append_tensor_lineage_event(
        model_ir=model_ir,
        event={
            "kind": "rename_tensor",
            "old_name": str(old_name),
            "new_name": str(new_name),
        },
    )


def _clone_quantization(quantization: Any) -> Any:
    if quantization is None:
        return None
    if isinstance(quantization, QuantParamIR):
        return QuantParamIR(
            scale=list(quantization.scale),
            zero_point=list(quantization.zero_point),
            quantized_dimension=int(quantization.quantized_dimension),
            min=list(quantization.min) if quantization.min is not None else None,
            max=list(quantization.max) if quantization.max is not None else None,
        )
    return copy.deepcopy(quantization)


def _quantize_prelu_alpha(
    alpha: np.ndarray,
    target_dtype: str,
) -> Tuple[np.ndarray, QuantParamIR]:
    alpha = np.asarray(alpha, dtype=np.float32)
    if str(target_dtype) == "INT8":
        max_abs = float(np.max(np.abs(alpha))) if alpha.size > 0 else 0.0
        scale = max(max_abs / 127.0, 1e-8)
        quantized = np.clip(np.round(alpha / scale), -128, 127).astype(np.int8)
        return quantized, QuantParamIR(
            scale=[float(scale)],
            zero_point=[0],
            quantized_dimension=0,
        )
    if str(target_dtype) == "UINT8":
        mn = float(np.min(alpha)) if alpha.size > 0 else 0.0
        mx = float(np.max(alpha)) if alpha.size > 0 else 0.0
        scale = max((mx - mn) / 255.0, 1e-8)
        zp = int(np.round(-mn / scale))
        zp = int(np.clip(zp, 0, 255))
        quantized = np.clip(np.round(alpha / scale) + zp, 0, 255).astype(np.uint8)
        return quantized, QuantParamIR(
            scale=[float(scale)],
            zero_point=[int(zp)],
            quantized_dimension=0,
        )
    raise NotImplementedError(f"Quantized PRELU alpha requires INT8/UINT8. got={target_dtype}")


def _quantize_tensor_per_tensor(
    values: np.ndarray,
    target_dtype: str,
) -> Tuple[np.ndarray, QuantParamIR]:
    values = np.asarray(values, dtype=np.float32)
    if str(target_dtype) == "INT8":
        max_abs = float(np.max(np.abs(values))) if values.size > 0 else 0.0
        scale = max(max_abs / 127.0, 1e-8)
        quantized = np.clip(np.round(values / scale), -128, 127).astype(np.int8)
        return quantized, QuantParamIR(
            scale=[float(scale)],
            zero_point=[0],
            quantized_dimension=0,
        )
    if str(target_dtype) == "UINT8":
        mn = float(np.min(values)) if values.size > 0 else 0.0
        mx = float(np.max(values)) if values.size > 0 else 0.0
        scale = max((mx - mn) / 255.0, 1e-8)
        zp = int(np.round(-mn / scale))
        zp = int(np.clip(zp, 0, 255))
        quantized = np.clip(np.round(values / scale) + zp, 0, 255).astype(np.uint8)
        return quantized, QuantParamIR(
            scale=[float(scale)],
            zero_point=[int(zp)],
            quantized_dimension=0,
        )
    raise NotImplementedError(f"Per-tensor quantization supports INT8/UINT8 only. got={target_dtype}")


def _get_per_tensor_scale_zero_point(quantization: Any) -> Optional[Tuple[float, int]]:
    if quantization is None:
        return None
    if not _is_per_tensor_quantization(quantization):
        return None
    if isinstance(quantization, QuantParamIR):
        if len(list(quantization.scale)) == 0 or len(list(quantization.zero_point)) == 0:
            return None
        return float(quantization.scale[0]), int(quantization.zero_point[0])
    if isinstance(quantization, dict):
        try:
            scale = np.asarray(quantization.get("scale", []), dtype=np.float32).reshape(-1)
            zero_point = np.asarray(quantization.get("zero_point", []), dtype=np.int64).reshape(-1)
            if scale.size == 0 or zero_point.size == 0:
                return None
            return float(scale[0]), int(zero_point[0])
        except Exception:
            return None
    return None


def _is_same_per_tensor_quantization(
    quantization_a: Any,
    quantization_b: Any,
    *,
    rtol: float = 1e-6,
    atol: float = 1e-8,
) -> bool:
    qparams_a = _get_per_tensor_scale_zero_point(quantization_a)
    qparams_b = _get_per_tensor_scale_zero_point(quantization_b)
    if qparams_a is None or qparams_b is None:
        return False
    scale_a, zp_a = qparams_a
    scale_b, zp_b = qparams_b
    if int(zp_a) != int(zp_b):
        return False
    return bool(np.isclose(float(scale_a), float(scale_b), rtol=rtol, atol=atol))


def _quant_scale_count(quantization: Any) -> int:
    if quantization is None:
        return 0
    if isinstance(quantization, QuantParamIR):
        return len(list(quantization.scale))
    if isinstance(quantization, dict):
        scale = quantization.get("scale", None)
        if scale is None:
            return 0
        if isinstance(scale, (list, tuple)):
            return len(list(scale))
        try:
            return int(np.asarray(scale).size)
        except Exception:
            return 0
    return 0


def _is_per_tensor_quantization(quantization: Any) -> bool:
    count = _quant_scale_count(quantization)
    return count <= 1


def _permute_shape(shape: Optional[List[int]], perm: List[int]) -> Optional[List[int]]:
    if shape is None:
        return None
    rank = len(shape)
    if len(perm) != rank:
        return None
    if sorted(perm) != [int(i) for i in range(rank)]:
        return None
    return [int(shape[int(axis)]) for axis in perm]


def _shapes_equal(shape_a: Optional[List[int]], shape_b: Optional[List[int]]) -> bool:
    if shape_a is None or shape_b is None:
        return False
    if len(shape_a) != len(shape_b):
        return False
    return all(int(a) == int(b) for a, b in zip(shape_a, shape_b))


def _is_unknown_shape(shape: Optional[List[int]]) -> bool:
    if shape is None:
        return True
    if len(shape) == 0:
        return True
    if any(int(dim) < 0 for dim in shape):
        return True
    # Internal placeholder shape used before static shape propagation.
    if len(shape) == 1 and int(shape[0]) == 1:
        return True
    return False


def _shapes_match_if_known(shape_a: Optional[List[int]], shape_b: Optional[List[int]]) -> bool:
    if _is_unknown_shape(shape_a) or _is_unknown_shape(shape_b):
        return True
    return _shapes_equal(shape_a, shape_b)


def _all_per_tensor_quantized(tensors: List[Optional[TensorIR]]) -> bool:
    for tensor in tensors:
        if tensor is None:
            continue
        if tensor.quantization is None:
            continue
        if not _is_per_tensor_quantization(tensor.quantization):
            return False
    return True


def _resolve_reshape_new_shape_from_static_input(
    new_shape: List[int],
    input_signature: Optional[List[int]],
    allow_zero: Optional[bool] = None,
) -> Optional[List[int]]:
    if len(new_shape) == 0:
        return None
    candidate = [int(v) for v in new_shape]

    if any(int(dim) == 0 for dim in candidate):
        # Without allowzero metadata we avoid rewriting zero-dim requests.
        if allow_zero is None:
            return None
        if allow_zero:
            return None
        if input_signature is None or len(input_signature) == 0:
            return None
        for idx, dim in enumerate(candidate):
            if int(dim) != 0:
                continue
            if idx >= len(input_signature):
                return None
            in_dim = int(input_signature[idx])
            if in_dim <= 0:
                return None
            candidate[idx] = int(in_dim)

    if all(int(dim) >= 0 for dim in candidate):
        if input_signature is None or len(input_signature) == 0:
            return list(candidate)
        if any(int(dim) <= 0 for dim in input_signature):
            return list(candidate)

        input_product = int(np.prod(np.asarray(input_signature, dtype=np.int64)))
        if input_product <= 0:
            return list(candidate)
        target_product = int(np.prod(np.asarray(candidate, dtype=np.int64)))
        if target_product == input_product:
            return list(candidate)

        # Stale reshape constants can appear after late layout rewrites.
        # If exactly one dimension can be re-inferred from static input size,
        # repair that dimension instead of keeping an invalid constant.
        inferable_dims: List[Tuple[int, int]] = []
        for idx in range(len(candidate)):
            other_product = 1
            valid = True
            for j, dim in enumerate(candidate):
                if j == idx:
                    continue
                d = int(dim)
                if d <= 0:
                    valid = False
                    break
                other_product *= d
            if not valid or other_product <= 0:
                continue
            if input_product % other_product != 0:
                continue
            inferred_dim = int(input_product // other_product)
            if inferred_dim <= 0:
                continue
            inferable_dims.append((int(idx), int(inferred_dim)))

        if len(inferable_dims) == 1:
            dim_idx, inferred_dim = inferable_dims[0]
            repaired = [int(v) for v in candidate]
            repaired[dim_idx] = int(inferred_dim)
            return repaired

        return None

    minus_one_indices = [idx for idx, dim in enumerate(candidate) if int(dim) == -1]
    if len(minus_one_indices) != 1:
        return None
    if input_signature is None or len(input_signature) == 0:
        return None
    if any(int(dim) <= 0 for dim in input_signature):
        return None

    known_product = 1
    for dim in candidate:
        if int(dim) == -1:
            continue
        if int(dim) <= 0:
            return None
        known_product *= int(dim)
    if known_product <= 0:
        return None

    input_product = int(np.prod(np.asarray(input_signature, dtype=np.int64)))
    if input_product <= 0 or input_product % known_product != 0:
        return None
    inferred = int(input_product // known_product)
    if inferred <= 0:
        return None
    candidate[minus_one_indices[0]] = inferred
    return candidate


def _resolve_dynamic_reshape_shapes(model_ir: ModelIR) -> Dict[str, int]:
    resolved_count = 0
    for op in model_ir.operators:
        if str(op.op_type) != "RESHAPE":
            continue
        if bool(op.options.get("preserveDynamicShape", False)):
            continue
        if len(op.inputs) < 1 or len(op.outputs) != 1:
            continue

        raw_new_shape = op.options.get("onnxRawNewShape", op.options.get("newShape", []))
        try:
            new_shape = [int(v) for v in np.asarray(raw_new_shape).reshape(-1).tolist()]
        except Exception:
            continue

        input_tensor = model_ir.tensors.get(op.inputs[0], None)
        if input_tensor is None:
            continue
        input_signature = (
            list(input_tensor.shape_signature)
            if input_tensor.shape_signature is not None
            else list(input_tensor.shape)
        )
        resolved_shape = _resolve_reshape_new_shape_from_static_input(
            new_shape=new_shape,
            input_signature=input_signature,
            allow_zero=(
                bool(op.options.get("allowZero"))
                if "allowZero" in op.options
                else None
            ),
        )
        if resolved_shape is None:
            continue

        changed = False
        if [int(v) for v in new_shape] != [int(v) for v in resolved_shape]:
            op.options["newShape"] = [int(v) for v in resolved_shape]
            changed = True

        if len(op.inputs) >= 2:
            shape_tensor = model_ir.tensors.get(op.inputs[1], None)
            if shape_tensor is not None:
                existing_shape_data = None
                if shape_tensor.data is not None:
                    existing_shape_data = [
                        int(v) for v in np.asarray(shape_tensor.data).reshape(-1).tolist()
                    ]
                if existing_shape_data != [int(v) for v in resolved_shape]:
                    shape_tensor.data = np.asarray(resolved_shape, dtype=np.int32)
                    shape_tensor.dtype = "INT32"
                    shape_tensor.shape = [int(len(resolved_shape))]
                    shape_tensor.shape_signature = [int(len(resolved_shape))]
                    changed = True

        output_tensor = model_ir.tensors.get(op.outputs[0], None)
        if output_tensor is not None:
            output_shape = list(output_tensor.shape)
            output_signature = (
                list(output_tensor.shape_signature)
                if output_tensor.shape_signature is not None
                else None
            )
            if output_shape != [int(v) for v in resolved_shape] or output_signature != [int(v) for v in resolved_shape]:
                output_tensor.shape = [int(v) for v in resolved_shape]
                output_tensor.shape_signature = [int(v) for v in resolved_shape]
                changed = True

        if changed:
            resolved_count += 1

    return {"resolved_dynamic_reshape_shapes": int(resolved_count)}


def _sanitize_hardswish_tensor_shapes(model_ir: ModelIR) -> Dict[str, int]:
    """
    HARD_SWISH must preserve input shape exactly.
    Late transpose/layout rewrites can occasionally leave stale output metadata.
    """
    fixed = 0
    for op in model_ir.operators:
        if str(op.op_type) != "HARD_SWISH":
            continue
        if len(op.inputs) < 1 or len(op.outputs) != 1:
            continue

        input_name = str(op.inputs[0])
        output_name = str(op.outputs[0])
        input_tensor = model_ir.tensors.get(input_name, None)
        output_tensor = model_ir.tensors.get(output_name, None)
        if input_tensor is None or output_tensor is None:
            continue
        if input_tensor.shape is None or len(list(input_tensor.shape)) == 0:
            continue

        input_shape = [int(v) for v in list(input_tensor.shape)]
        input_signature_current = (
            [int(v) for v in list(input_tensor.shape_signature)]
            if input_tensor.shape_signature is not None
            else []
        )
        if _is_fully_known_positive_shape(input_shape):
            input_signature = [int(v) for v in list(input_shape)]
        else:
            input_signature = (
                [int(v) for v in list(input_signature_current)]
                if len(input_signature_current) > 0
                else [int(v) for v in list(input_shape)]
            )
        output_shape = (
            [int(v) for v in list(output_tensor.shape)]
            if output_tensor.shape is not None
            else []
        )
        output_signature = (
            [int(v) for v in list(output_tensor.shape_signature)]
            if output_tensor.shape_signature is not None
            else [int(v) for v in list(output_shape)]
        )

        if (
            input_signature_current == input_signature
            and output_shape == input_shape
            and output_signature == input_signature
        ):
            continue

        input_tensor.shape_signature = [int(v) for v in list(input_signature)]
        output_tensor.shape = [int(v) for v in list(input_shape)]
        output_tensor.shape_signature = [int(v) for v in list(input_signature)]
        fixed += 1

    return {"sanitized_hardswish_tensor_shapes": int(fixed)}


def _sanitize_squeeze_axes_with_static_input_shapes(model_ir: ModelIR) -> Dict[str, int]:
    """
    Keep SQUEEZE axes consistent with concrete input metadata.

    Late rewrite passes can leave a SQUEEZE axis targeting a non-singleton
    dimension, which crashes LiteRT during `allocate_tensors()`.
    This pass normalizes axes and repairs static metadata conservatively:
    - invalid / duplicated axes are removed
    - non-singleton axes are forced to singleton on non-constant inputs
    - for constant inputs whose payload shape proves non-singleton axes,
      those axes are dropped
    """
    sanitized_ops = 0
    repaired_input_dims = 0
    updated_output_shapes = 0

    for op in model_ir.operators:
        if str(op.op_type) != "SQUEEZE":
            continue
        if len(op.inputs) < 1 or len(op.outputs) != 1:
            continue

        input_name = str(op.inputs[0])
        output_name = str(op.outputs[0])
        input_tensor = model_ir.tensors.get(input_name, None)
        output_tensor = model_ir.tensors.get(output_name, None)
        if input_tensor is None or output_tensor is None:
            continue
        if not _is_fully_known_positive_shape(input_tensor.shape):
            continue

        input_shape = [int(v) for v in list(input_tensor.shape)]
        rank = len(input_shape)
        input_signature = (
            [int(v) for v in list(input_tensor.shape_signature)]
            if input_tensor.shape_signature is not None
            and len(list(input_tensor.shape_signature)) == rank
            else [int(v) for v in list(input_shape)]
        )

        options = dict(op.options) if isinstance(op.options, dict) else {}
        raw_axes = _parse_axes_option(options.get("squeezeDims", []))

        normalized_axes: List[int] = []
        axes_modified = False
        for axis in raw_axes:
            a = int(axis)
            if a < 0:
                a += int(rank)
            if a < 0 or a >= int(rank):
                axes_modified = True
                continue
            if int(a) in normalized_axes:
                axes_modified = True
                continue
            normalized_axes.append(int(a))

        data_shape: Optional[List[int]] = None
        if input_tensor.data is not None:
            try:
                data_arr = np.asarray(input_tensor.data)
                if int(data_arr.ndim) == int(rank):
                    data_shape = [int(v) for v in list(data_arr.shape)]
            except Exception:
                data_shape = None

        sanitized_axes: List[int] = []
        repaired_shape = [int(v) for v in list(input_shape)]
        repaired_signature = [int(v) for v in list(input_signature)]
        for axis in normalized_axes:
            current_dim = int(repaired_shape[axis])
            if current_dim == 1:
                sanitized_axes.append(int(axis))
                if int(repaired_signature[axis]) != 1:
                    repaired_signature[axis] = 1
                continue

            can_force_singleton = (
                data_shape is None
                or int(axis) >= len(data_shape)
                or int(data_shape[axis]) == 1
            )
            if can_force_singleton:
                repaired_shape[axis] = 1
                repaired_signature[axis] = 1
                sanitized_axes.append(int(axis))
                repaired_input_dims += 1
                continue

            axes_modified = True

        input_changed = (
            repaired_shape != [int(v) for v in list(input_tensor.shape)]
            or (
                input_tensor.shape_signature is None
                or [int(v) for v in list(input_tensor.shape_signature)] != repaired_signature
            )
        )
        if input_changed:
            input_tensor.shape = [int(v) for v in list(repaired_shape)]
            input_tensor.shape_signature = [int(v) for v in list(repaired_signature)]

        if axes_modified or sanitized_axes != raw_axes:
            options["squeezeDims"] = [int(v) for v in sanitized_axes]
            op.options = options
            sanitized_ops += 1

        out_shape, out_signature = _infer_squeeze_output_shape_and_signature(
            input_shape=[int(v) for v in list(input_tensor.shape)],
            input_signature=(
                [int(v) for v in list(input_tensor.shape_signature)]
                if input_tensor.shape_signature is not None
                else [int(v) for v in list(input_tensor.shape)]
            ),
            squeeze_axes=[int(v) for v in list(sanitized_axes)],
        )
        if out_shape is None or out_signature is None:
            continue
        if not _is_fully_known_positive_shape(out_shape):
            continue

        if (
            [int(v) for v in list(output_tensor.shape)] != [int(v) for v in list(out_shape)]
            or output_tensor.shape_signature is None
            or [int(v) for v in list(output_tensor.shape_signature)] != [int(v) for v in list(out_signature)]
        ):
            output_tensor.shape = [int(v) for v in list(out_shape)]
            output_tensor.shape_signature = [int(v) for v in list(out_signature)]
            updated_output_shapes += 1

    return {
        "sanitized_squeeze_axes_with_static_input_shapes": int(sanitized_ops),
        "repaired_squeeze_input_singleton_dims": int(repaired_input_dims),
        "updated_squeeze_output_shapes": int(updated_output_shapes),
    }


def _sanitize_wrong_way_nchw_to_nhwc_transpose_before_conv(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove invalid NCHW->NHWC transposes that are applied to already-NHWC tensors
    and break downstream CONV_2D channel alignment.
    """
    removed = 0
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    model_outputs = set(str(v) for v in model_ir.outputs)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for op_idx, op in enumerate(model_ir.operators):
            if str(op.op_type) != "TRANSPOSE" or len(op.inputs) < 2 or len(op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, op) != perm_nchw_to_nhwc:
                continue

            in_name = str(op.inputs[0])
            out_name = str(op.outputs[0])
            if out_name in model_outputs:
                continue

            in_tensor = model_ir.tensors.get(in_name, None)
            out_tensor = model_ir.tensors.get(out_name, None)
            if (
                in_tensor is None
                or out_tensor is None
                or len(list(in_tensor.shape)) != 4
                or len(list(out_tensor.shape)) != 4
            ):
                continue

            user_indices = [int(v) for v in consumers.get(out_name, [])]
            if len(user_indices) == 0:
                continue

            remove_this = True
            in_c = int(in_tensor.shape[3])
            out_c = int(out_tensor.shape[3])
            for user_idx in user_indices:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) != "CONV_2D"
                    or len(user_op.inputs) < 2
                    or str(user_op.inputs[0]) != out_name
                ):
                    remove_this = False
                    break
                filter_tensor = model_ir.tensors.get(str(user_op.inputs[1]), None)
                if filter_tensor is None or len(list(filter_tensor.shape)) != 4:
                    remove_this = False
                    break
                expected_c = int(filter_tensor.shape[3])
                if not (in_c == expected_c and out_c != expected_c):
                    remove_this = False
                    break

            if not remove_this:
                continue

            _replace_tensor_inputs(model_ir, out_name, in_name)
            del model_ir.operators[int(op_idx)]
            removed += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"sanitized_wrong_way_nchw_to_nhwc_transpose_before_conv": int(removed)}


def _repair_rank4_binary_layout_mismatch_with_transpose_adapter(model_ir: ModelIR) -> Dict[str, int]:
    """
    Repair rank-4 layout mismatches for elementwise binary ops by inserting a
    minimal transpose adapter on one input when shapes are pure NHWC/NCHW
    permutations of each other.
    """
    inserted = 0
    binary_ops = {"ADD", "MUL", "SUB", "DIV", "MAXIMUM", "MINIMUM"}
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nhwc_to_nchw = [0, 3, 1, 2]

    def _make_unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        for op_idx, op in enumerate(model_ir.operators):
            op_type = str(op.op_type)
            if op_type not in binary_ops or len(op.inputs) != 2 or len(op.outputs) != 1:
                continue

            in0_name = str(op.inputs[0])
            in1_name = str(op.inputs[1])
            t0 = model_ir.tensors.get(in0_name, None)
            t1 = model_ir.tensors.get(in1_name, None)
            if t0 is None or t1 is None:
                continue
            s0 = [int(v) for v in list(t0.shape)]
            s1 = [int(v) for v in list(t1.shape)]
            if len(s0) != 4 or len(s1) != 4:
                continue
            if any(int(v) <= 0 for v in s0 + s1):
                continue
            if s0 == s1:
                continue

            perm_to_use: Optional[List[int]] = None
            if s0 == [int(s1[idx]) for idx in perm_nchw_to_nhwc]:
                perm_to_use = [int(v) for v in list(perm_nchw_to_nhwc)]
            elif s0 == [int(s1[idx]) for idx in perm_nhwc_to_nchw]:
                perm_to_use = [int(v) for v in list(perm_nhwc_to_nchw)]
            else:
                continue

            perm_name = _make_unique_tensor_name(f"{in1_name}_layout_fix_perm")
            adapted_name = _make_unique_tensor_name(f"{in1_name}_layout_fix")
            model_ir.tensors[perm_name] = TensorIR(
                name=perm_name,
                dtype="INT32",
                shape=[4],
                shape_signature=[4],
                data=np.asarray(perm_to_use, dtype=np.int32),
                is_variable=False,
            )
            model_ir.tensors[adapted_name] = TensorIR(
                name=adapted_name,
                dtype=str(t1.dtype),
                shape=[int(v) for v in list(s0)],
                shape_signature=[int(v) for v in list(s0)],
                data=None,
                is_variable=False,
                quantization=_clone_quantization(t1.quantization),
            )
            model_ir.operators.insert(
                int(op_idx),
                OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[in1_name, perm_name],
                    outputs=[adapted_name],
                ),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=op,
                input_index=1,
                new_input_name=adapted_name,
            )
            inserted += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"inserted_rank4_binary_layout_fix_transpose": int(inserted)}


def _sanitize_static_shape_signature_consistency(model_ir: ModelIR) -> Dict[str, int]:
    """
    For fully static tensors, keep shape_signature consistent with runtime shape.

    Notes:
    - Keep dynamic `-1` only for ONNX graph-boundary tensors that were dynamic
      in the source model (input/output contract).
    - Preserve dynamic `-1` on internal tensors only when they are reachable
      from those dynamic graph boundaries through operator dependencies.
    - Internal tensors are auto-completed: if runtime `shape` is fully static,
      `shape_signature` is overwritten to the same static shape.
    """
    fixed = 0
    preserved_dynamic_boundary = 0
    preserved_dynamic_leading_axis = 0
    preserved_dynamic_lineage = 0
    dynamic_boundary_names = set()
    for key in (
        "onnx_dynamic_input_tensor_names",
        "onnx_dynamic_output_tensor_names",
    ):
        names = model_ir.metadata.get(key, [])
        if isinstance(names, list):
            dynamic_boundary_names.update(str(v) for v in names if str(v) != "")
    dynamic_boundary_signature_map = model_ir.metadata.get(
        "dynamic_boundary_shape_signature_map", {}
    )
    if not isinstance(dynamic_boundary_signature_map, dict):
        dynamic_boundary_signature_map = {}
    graph_output_names = set(str(v) for v in list(model_ir.outputs))
    producer_map = _build_tensor_producer_map(model_ir)
    dynamic_lineage_root_names = set(dynamic_boundary_names)
    for tensor_name, producer_idx in producer_map.items():
        if int(producer_idx) < 0 or int(producer_idx) >= len(model_ir.operators):
            continue
        if str(model_ir.operators[int(producer_idx)].op_type) != "WHERE":
            continue
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None:
            continue
        signature = (
            [int(v) for v in list(tensor.shape_signature)]
            if tensor.shape_signature is not None
            else [int(v) for v in list(tensor.shape)]
        )
        if len(signature) >= 1 and int(signature[0]) < 0:
            dynamic_lineage_root_names.add(str(tensor_name))
    dynamic_lineage_cache: Dict[str, bool] = {}
    dynamic_lineage_visiting: set[str] = set()

    def _has_dynamic_boundary_lineage(tensor_name: str) -> bool:
        key = str(tensor_name)
        cached = dynamic_lineage_cache.get(key, None)
        if cached is not None:
            return bool(cached)
        if key in dynamic_lineage_root_names:
            dynamic_lineage_cache[key] = True
            return True
        if key in dynamic_lineage_visiting:
            dynamic_lineage_cache[key] = False
            return False
        tensor = model_ir.tensors.get(key, None)
        if tensor is None:
            dynamic_lineage_cache[key] = False
            return False
        if tensor.data is not None:
            dynamic_lineage_cache[key] = False
            return False
        producer_idx = producer_map.get(key, None)
        if producer_idx is None:
            dynamic_lineage_cache[key] = False
            return False
        dynamic_lineage_visiting.add(key)
        producer = model_ir.operators[int(producer_idx)]
        has_dynamic_ancestor = False
        for input_name in producer.inputs:
            parent_name = str(input_name)
            if parent_name == "":
                continue
            if _has_dynamic_boundary_lineage(parent_name):
                has_dynamic_ancestor = True
                break
        dynamic_lineage_visiting.discard(key)
        dynamic_lineage_cache[key] = bool(has_dynamic_ancestor)
        return bool(has_dynamic_ancestor)

    for tensor in model_ir.tensors.values():
        if tensor.shape is None:
            continue
        shape = [int(v) for v in list(tensor.shape)]
        if len(shape) == 0:
            if tensor.shape_signature is None:
                tensor.shape_signature = []
                fixed += 1
            continue
        if not _is_fully_known_positive_shape(shape):
            continue

        boundary_signature = dynamic_boundary_signature_map.get(str(tensor.name), None)
        if isinstance(boundary_signature, list) and len(boundary_signature) == len(shape):
            normalized_boundary_signature = [
                int(-1 if int(v) < 0 else shape[idx])
                for idx, v in enumerate(boundary_signature)
            ]
            if any(int(v) < 0 for v in normalized_boundary_signature):
                if tensor.shape_signature != normalized_boundary_signature:
                    tensor.shape_signature = list(normalized_boundary_signature)
                    fixed += 1
                preserved_dynamic_boundary += 1
                continue

        signature = (
            [int(v) for v in list(tensor.shape_signature)]
            if tensor.shape_signature is not None
            else None
        )
        if signature is None:
            tensor.shape_signature = [int(v) for v in list(shape)]
            fixed += 1
            continue
        if len(signature) != len(shape):
            tensor.shape_signature = [int(v) for v in list(shape)]
            fixed += 1
            continue
        if any(int(v) < 0 for v in signature):
            negative_axes = [int(i) for i, v in enumerate(signature) if int(v) < 0]
            trailing_axes_static = all(
                int(signature[idx]) > 0 for idx in range(1, len(signature))
            )
            producer_idx = producer_map.get(str(tensor.name), None)
            producer_op_type = (
                str(model_ir.operators[int(producer_idx)].op_type)
                if producer_idx is not None and int(producer_idx) < len(model_ir.operators)
                else ""
            )
            if str(tensor.name) in dynamic_lineage_root_names:
                preserved_dynamic_boundary += 1
                continue
            if (
                producer_op_type == "WHERE"
                and negative_axes == [0]
                and trailing_axes_static
            ):
                preserved_dynamic_leading_axis += 1
                continue
            has_dynamic_lineage = _has_dynamic_boundary_lineage(str(tensor.name))
            if negative_axes == [0] and trailing_axes_static:
                if str(tensor.name) in graph_output_names:
                    preserved_dynamic_leading_axis += 1
                    continue
                if has_dynamic_lineage:
                    preserved_dynamic_leading_axis += 1
                    continue
            if has_dynamic_lineage:
                if negative_axes == [0] and trailing_axes_static:
                    preserved_dynamic_leading_axis += 1
                else:
                    preserved_dynamic_lineage += 1
                continue
            tensor.shape_signature = [int(v) for v in list(shape)]
            fixed += 1
            continue
        if signature != shape:
            tensor.shape_signature = [int(v) for v in list(shape)]
            fixed += 1

    return {
        "sanitized_static_shape_signature_consistency": int(fixed),
        "preserved_dynamic_boundary_shape_signature": int(preserved_dynamic_boundary),
        "preserved_dynamic_leading_axis_shape_signature": int(
            preserved_dynamic_leading_axis
        ),
        "preserved_dynamic_lineage_shape_signature": int(
            preserved_dynamic_lineage
        ),
    }


def _realign_dynamic_boundary_shape_signature_map(model_ir: ModelIR) -> Dict[str, int]:
    signature_map = model_ir.metadata.get("dynamic_boundary_shape_signature_map", {})
    if not isinstance(signature_map, dict):
        return {"realigned_dynamic_boundary_shape_signature_map": 0}

    updated = 0
    for tensor_name, boundary_signature in list(signature_map.items()):
        if not isinstance(boundary_signature, list):
            continue
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.shape is None:
            continue
        aligned = _align_boundary_signature_to_current_shape(
            boundary_signature=[int(v) for v in list(boundary_signature)],
            current_shape=[int(v) for v in list(tensor.shape)],
        )
        if aligned is None:
            continue
        if [int(v) for v in list(boundary_signature)] != [int(v) for v in list(aligned)]:
            signature_map[str(tensor_name)] = [int(v) for v in list(aligned)]
            updated += 1

    model_ir.metadata["dynamic_boundary_shape_signature_map"] = signature_map
    return {"realigned_dynamic_boundary_shape_signature_map": int(updated)}


def _is_fully_known_positive_shape(shape: Optional[List[int]]) -> bool:
    if shape is None or len(shape) == 0:
        return False
    return all(int(dim) > 0 for dim in shape)


def _read_const_ints_from_tensor(tensor: Optional[TensorIR]) -> Optional[List[int]]:
    if tensor is None or tensor.data is None:
        return None
    try:
        return [int(v) for v in np.asarray(tensor.data).reshape(-1).tolist()]
    except Exception:
        return None


def _write_const_ints_to_tensor(tensor: Optional[TensorIR], values: List[int]) -> bool:
    if tensor is None:
        return False
    current = _read_const_ints_from_tensor(tensor)
    normalized = [int(v) for v in list(values)]
    if current == normalized:
        return False
    np_dtype = np.int32
    if tensor.data is not None:
        try:
            np_dtype = np.asarray(tensor.data).dtype
        except Exception:
            np_dtype = np.int32
    tensor.data = np.asarray(normalized, dtype=np_dtype)
    tensor.shape = [int(len(normalized))]
    tensor.shape_signature = [int(len(normalized))]
    return True


def _infer_slice_output_shape_and_resolved_params(
    input_shape: Optional[List[int]],
    begin_vals: Optional[List[int]],
    size_vals: Optional[List[int]],
) -> Tuple[Optional[List[int]], Optional[List[int]], Optional[List[int]]]:
    if not _is_fully_known_positive_shape(input_shape):
        return None, None, None
    if begin_vals is None or size_vals is None:
        return None, None, None

    in_shape = [int(v) for v in list(input_shape)]
    begin = [int(v) for v in list(begin_vals)]
    size = [int(v) for v in list(size_vals)]
    rank = len(in_shape)
    if len(begin) != rank or len(size) != rank:
        return None, None, None

    resolved_begin: List[int] = []
    resolved_size: List[int] = []
    out_shape: List[int] = []
    for axis, dim in enumerate(in_shape):
        b = int(begin[axis])
        if b < 0:
            b += int(dim)
        b = max(0, min(int(b), int(dim)))
        remain = max(int(dim) - int(b), 0)

        raw_size = int(size[axis])
        if raw_size == -1:
            s = int(remain)
        elif raw_size >= 0:
            s = int(raw_size)
        else:
            return None, None, None

        out_dim = max(min(int(s), int(remain)), 0)
        resolved_begin.append(int(b))
        resolved_size.append(int(s))
        out_shape.append(int(out_dim))

    return out_shape, resolved_begin, resolved_size


def _infer_slice_output_signature(
    *,
    input_shape: Optional[List[int]],
    input_signature: Optional[List[int]],
    begin_vals: Optional[List[int]],
    size_vals: Optional[List[int]],
) -> Optional[List[int]]:
    if not _is_fully_known_positive_shape(input_shape):
        return None
    if begin_vals is None or size_vals is None:
        return None

    in_shape = [int(v) for v in list(input_shape)]
    rank = len(in_shape)
    begin = [int(v) for v in list(begin_vals)]
    size = [int(v) for v in list(size_vals)]
    if len(begin) != rank or len(size) != rank:
        return None

    if input_signature is not None and len(list(input_signature)) == rank:
        in_signature = [int(v) for v in list(input_signature)]
    else:
        in_signature = [int(v) for v in list(in_shape)]

    out_signature: List[int] = []
    for axis, dim in enumerate(in_shape):
        b = int(begin[axis])
        if b < 0:
            b += int(dim)
        b = max(0, min(int(b), int(dim)))
        remain = max(int(dim) - int(b), 0)

        raw_size = int(size[axis])
        if raw_size == -1:
            if int(in_signature[axis]) < 0:
                out_signature.append(-1)
            else:
                out_signature.append(int(remain))
            continue
        if raw_size < 0:
            return None
        out_signature.append(int(max(min(int(raw_size), int(remain)), 0)))

    return out_signature


def _broadcast_static_shapes(
    shape_a: Optional[List[int]],
    shape_b: Optional[List[int]],
) -> Optional[List[int]]:
    if not _is_fully_known_positive_shape(shape_a) or not _is_fully_known_positive_shape(shape_b):
        return None
    a = [int(v) for v in list(shape_a)]
    b = [int(v) for v in list(shape_b)]
    rank = max(len(a), len(b))
    a = [1] * (rank - len(a)) + a
    b = [1] * (rank - len(b)) + b
    out: List[int] = []
    for dim_a, dim_b in zip(a, b):
        if int(dim_a) == int(dim_b):
            out.append(int(dim_a))
            continue
        if int(dim_a) == 1:
            out.append(int(dim_b))
            continue
        if int(dim_b) == 1:
            out.append(int(dim_a))
            continue
        return None
    return out


def _broadcast_shape_signatures(
    signature_a: Optional[List[int]],
    signature_b: Optional[List[int]],
) -> Optional[List[int]]:
    if signature_a is None or signature_b is None:
        return None
    a = [int(v) for v in list(signature_a)]
    b = [int(v) for v in list(signature_b)]
    rank = max(len(a), len(b))
    a = [1] * (rank - len(a)) + a
    b = [1] * (rank - len(b)) + b
    out: List[int] = []
    for dim_a, dim_b in zip(a, b):
        if int(dim_a) == int(dim_b):
            out.append(int(dim_a))
            continue
        if int(dim_a) == 1:
            out.append(-1 if int(dim_b) < 0 else int(dim_b))
            continue
        if int(dim_b) == 1:
            out.append(-1 if int(dim_a) < 0 else int(dim_a))
            continue
        if int(dim_a) < 0 and int(dim_b) < 0:
            out.append(-1)
            continue
        if int(dim_a) < 0 and int(dim_b) > 1:
            out.append(int(dim_b))
            continue
        if int(dim_b) < 0 and int(dim_a) > 1:
            out.append(int(dim_a))
            continue
        return None
    return out


def _infer_batch_matmul_output_shape_and_signature(
    shape_a: Optional[List[int]],
    shape_b: Optional[List[int]],
    signature_a: Optional[List[int]],
    signature_b: Optional[List[int]],
    adj_x: bool,
    adj_y: bool,
) -> Tuple[Optional[List[int]], Optional[List[int]]]:
    if not _is_fully_known_positive_shape(shape_a) or not _is_fully_known_positive_shape(shape_b):
        return None, None
    a_shape = [int(v) for v in list(shape_a)]
    b_shape = [int(v) for v in list(shape_b)]
    if len(a_shape) < 2 or len(b_shape) < 2:
        return None, None

    a_sig = (
        [int(v) for v in list(signature_a)]
        if signature_a is not None and len(list(signature_a)) == len(a_shape)
        else list(a_shape)
    )
    b_sig = (
        [int(v) for v in list(signature_b)]
        if signature_b is not None and len(list(signature_b)) == len(b_shape)
        else list(b_shape)
    )

    batch_shape = _broadcast_static_shapes(a_shape[:-2], b_shape[:-2])
    if batch_shape is None:
        return None, None

    a_m_idx = -1 if bool(adj_x) else -2
    a_k_idx = -2 if bool(adj_x) else -1
    b_k_idx = -1 if bool(adj_y) else -2
    b_n_idx = -2 if bool(adj_y) else -1

    a_m = int(a_shape[a_m_idx])
    a_k = int(a_shape[a_k_idx])
    b_k = int(b_shape[b_k_idx])
    b_n = int(b_shape[b_n_idx])

    a_k_sig = int(a_sig[a_k_idx])
    b_k_sig = int(b_sig[b_k_idx])
    if a_k != b_k and a_k_sig >= 0 and b_k_sig >= 0:
        return None, None

    out_shape = [int(v) for v in list(batch_shape)] + [int(a_m), int(b_n)]

    batch_sig = _broadcast_shape_signatures(a_sig[:-2], b_sig[:-2])
    if batch_sig is None:
        batch_sig = [int(v) for v in list(batch_shape)]
    out_sig_m = -1 if int(a_sig[a_m_idx]) < 0 else int(a_m)
    out_sig_n = -1 if int(b_sig[b_n_idx]) < 0 else int(b_n)
    out_signature = [int(v) for v in list(batch_sig)] + [int(out_sig_m), int(out_sig_n)]

    return out_shape, out_signature


def _infer_rank4_signature_from_input(
    *,
    input_signature: Optional[List[int]],
    output_shape: Optional[List[int]],
    existing_output_signature: Optional[List[int]] = None,
    propagate_channel: bool = False,
) -> Optional[List[int]]:
    if output_shape is None or len(list(output_shape)) != 4:
        return None
    signature = [int(v) for v in list(output_shape)]

    normalized_input_signature = (
        [int(v) for v in list(input_signature)]
        if input_signature is not None and len(list(input_signature)) == 4
        else None
    )
    dynamic_from_input = [False, False, False, False]
    if normalized_input_signature is not None:
        dynamic_from_input[0] = int(normalized_input_signature[0]) < 0
        dynamic_from_input[1] = int(normalized_input_signature[1]) < 0
        dynamic_from_input[2] = int(normalized_input_signature[2]) < 0
        dynamic_from_input[3] = bool(propagate_channel) and int(normalized_input_signature[3]) < 0

    # Preserve existing dynamic marks only when input-derived dynamics can explain
    # that axis. This avoids stale all-unknown placeholders dominating new
    # operator-local inferences (e.g. static channel axis from filters).
    if (
        existing_output_signature is not None
        and len(list(existing_output_signature)) == 4
    ):
        if normalized_input_signature is None:
            for axis in range(4):
                if int(existing_output_signature[axis]) < 0:
                    signature[axis] = -1
        else:
            for axis in range(4):
                if int(existing_output_signature[axis]) < 0 and bool(dynamic_from_input[axis]):
                    signature[axis] = -1

    if normalized_input_signature is not None:
        if int(normalized_input_signature[0]) < 0:
            signature[0] = -1
        if int(normalized_input_signature[1]) < 0:
            signature[1] = -1
        if int(normalized_input_signature[2]) < 0:
            signature[2] = -1
        if bool(propagate_channel) and int(normalized_input_signature[3]) < 0:
            signature[3] = -1
    return signature


def _normalize_reduce_axes_for_rank(
    axes: Optional[List[int]],
    rank: int,
) -> Optional[List[int]]:
    if axes is None:
        return None
    if rank < 0:
        return None
    normalized: List[int] = []
    for axis in list(axes):
        a = int(axis)
        if a < 0:
            a += int(rank)
        if a < 0 or a >= int(rank):
            return None
        if int(a) not in normalized:
            normalized.append(int(a))
    return normalized


def _infer_reduce_output_shape_and_signature(
    *,
    input_shape: Optional[List[int]],
    input_signature: Optional[List[int]],
    axes: Optional[List[int]],
    keep_dims: bool,
) -> Tuple[Optional[List[int]], Optional[List[int]]]:
    if input_shape is None:
        return None, None
    in_shape = [int(v) for v in list(input_shape)]
    rank = len(in_shape)
    if rank == 0:
        return list(in_shape), list(in_shape)
    normalized_axes = _normalize_reduce_axes_for_rank(axes, rank)
    if normalized_axes is None:
        return None, None

    if input_signature is not None and len(list(input_signature)) == rank:
        in_signature = [int(v) for v in list(input_signature)]
    else:
        in_signature = [int(v) for v in list(in_shape)]

    if bool(keep_dims):
        out_shape = [int(v) for v in list(in_shape)]
        out_signature = [int(v) for v in list(in_signature)]
        for axis in normalized_axes:
            out_shape[int(axis)] = 1
            out_signature[int(axis)] = 1
        return out_shape, out_signature

    reduced_axes = set(int(v) for v in normalized_axes)
    out_shape = [int(in_shape[idx]) for idx in range(rank) if idx not in reduced_axes]
    out_signature = [int(in_signature[idx]) for idx in range(rank) if idx not in reduced_axes]
    return out_shape, out_signature


def _parse_axes_option(raw_axes: Any) -> List[int]:
    if raw_axes is None:
        return []
    if isinstance(raw_axes, (list, tuple, np.ndarray)):
        return [int(v) for v in list(raw_axes)]
    return [int(raw_axes)]


def _normalize_squeeze_axes_for_rank(
    axes: List[int],
    rank: int,
) -> Optional[List[int]]:
    normalized: List[int] = []
    for axis in list(axes):
        a = int(axis)
        if a < 0:
            a += int(rank)
        if a < 0 or a >= int(rank):
            return None
        if int(a) not in normalized:
            normalized.append(int(a))
    return normalized


def _infer_squeeze_output_shape_and_signature(
    *,
    input_shape: Optional[List[int]],
    input_signature: Optional[List[int]],
    squeeze_axes: Optional[List[int]],
) -> Tuple[Optional[List[int]], Optional[List[int]]]:
    if input_shape is None:
        return None, None
    in_shape = [int(v) for v in list(input_shape)]
    rank = len(in_shape)
    if input_signature is not None and len(list(input_signature)) == rank:
        in_signature = [int(v) for v in list(input_signature)]
    else:
        in_signature = [int(v) for v in list(in_shape)]

    axes_list = [int(v) for v in list(squeeze_axes)] if squeeze_axes is not None else []
    normalized_axes = _normalize_squeeze_axes_for_rank(axes_list, rank)
    if normalized_axes is None:
        return None, None
    if len(normalized_axes) == 0:
        normalized_axes = [
            int(idx)
            for idx in range(rank)
            if idx < len(in_signature) and int(in_signature[idx]) == 1
        ]
        if len(normalized_axes) == 0:
            normalized_axes = [
                int(idx)
                for idx, dim in enumerate(in_shape)
                if int(dim) == 1
            ]

    remove_axes = set(int(v) for v in normalized_axes)
    out_shape = [int(in_shape[idx]) for idx in range(rank) if idx not in remove_axes]
    out_signature = [int(in_signature[idx]) for idx in range(rank) if idx not in remove_axes]
    return out_shape, out_signature


def _infer_conv_out_dim(
    in_size: int,
    kernel_size: int,
    stride: int,
    dilation: int,
    padding: str,
) -> Optional[int]:
    if any(int(v) <= 0 for v in [in_size, kernel_size, stride, dilation]):
        return None
    effective_kernel = int((int(kernel_size) - 1) * int(dilation) + 1)
    mode = str(padding).upper()
    if mode == "SAME":
        return int((int(in_size) + int(stride) - 1) // int(stride))
    if mode == "VALID":
        return int((int(in_size) - int(effective_kernel)) // int(stride) + 1)
    return None


def _reconcile_static_tensor_shapes(model_ir: ModelIR) -> Dict[str, int]:
    """
    Recompute static tensor shapes after aggressive graph rewrites.

    Some transpose-bridge optimizations intentionally relax local shape guards and can
    leave stale static metadata. This pass performs a conservative forward fixed-point
    shape propagation and syncs `shape` / `shape_signature` for common TFLite ops.
    """
    updated_tensors = 0

    def _update_tensor_shape(
        tensor_name: str,
        new_shape: Optional[List[int]],
        new_shape_signature: Optional[List[int]] = None,
    ) -> bool:
        nonlocal updated_tensors
        if new_shape is None:
            return False
        if not _is_fully_known_positive_shape(new_shape):
            return False
        tensor = model_ir.tensors.get(tensor_name, None)
        if tensor is None:
            return False
        normalized = [int(v) for v in list(new_shape)]
        if new_shape_signature is not None and len(list(new_shape_signature)) == len(normalized):
            signature = [int(v) for v in list(new_shape_signature)]
        else:
            existing_signature = (
                list(tensor.shape_signature)
                if tensor.shape_signature is not None and len(list(tensor.shape_signature)) == len(normalized)
                else None
            )
            if existing_signature is None:
                signature = [int(v) for v in list(normalized)]
            else:
                # Preserve unknown dims inferred upstream to avoid collapsing dynamic axes
                # into placeholder static 1s during conservative shape reconciliation.
                signature = [
                    int(existing_signature[idx]) if int(existing_signature[idx]) < 0 else int(normalized[idx])
                    for idx in range(len(normalized))
                ]
        if tensor.shape == normalized and tensor.shape_signature == signature:
            return False
        tensor.shape = normalized
        tensor.shape_signature = signature
        updated_tensors += 1
        return True

    max_passes = 32
    for _ in range(max_passes):
        changed = False
        for op in model_ir.operators:
            op_type = str(op.op_type)
            inputs = [str(v) for v in list(op.inputs)]
            outputs = [str(v) for v in list(op.outputs)]
            if len(outputs) == 0:
                continue

            # Pass-through ops: output shape == first input shape.
            if op_type in {
                "QUANTIZE",
                "DEQUANTIZE",
                "SOFTMAX",
                "LOGISTIC",
                "TANH",
                "RELU",
                "RELU6",
                "RELU_0_TO_1",
                "PRELU",
                "HARD_SWISH",
                "LEAKY_RELU",
                "GELU",
                "CAST",
                "NEG",
                "FLOOR",
            }:
                if len(inputs) >= 1:
                    in_tensor = model_ir.tensors.get(inputs[0], None)
                    if in_tensor is not None and _is_fully_known_positive_shape(in_tensor.shape):
                        in_signature = (
                            list(in_tensor.shape_signature)
                            if in_tensor.shape_signature is not None
                            else list(in_tensor.shape)
                        )
                        changed |= _update_tensor_shape(
                            outputs[0],
                            list(in_tensor.shape),
                            in_signature,
                        )
                continue

            if op_type == "TRANSPOSE" and len(inputs) >= 2 and len(outputs) == 1:
                in_tensor = model_ir.tensors.get(inputs[0], None)
                out_tensor = model_ir.tensors.get(outputs[0], None)
                perm_tensor = model_ir.tensors.get(inputs[1], None)
                perm = _read_const_ints_from_tensor(perm_tensor)
                if perm is None:
                    continue
                perm = [int(v) for v in perm]
                if in_tensor is not None and _is_fully_known_positive_shape(in_tensor.shape):
                    out_shape = _permute_shape(list(in_tensor.shape), perm)
                    in_signature = (
                        list(in_tensor.shape_signature)
                        if in_tensor.shape_signature is not None
                        else list(in_tensor.shape)
                    )
                    out_signature = _permute_shape(in_signature, perm)
                    changed |= _update_tensor_shape(
                        outputs[0],
                        out_shape,
                        out_signature,
                    )
                if out_tensor is not None and _is_fully_known_positive_shape(out_tensor.shape):
                    inv_perm = _invert_perm(perm)
                    if inv_perm is not None:
                        in_shape = _permute_shape(list(out_tensor.shape), inv_perm)
                        out_signature = (
                            list(out_tensor.shape_signature)
                            if out_tensor.shape_signature is not None
                            else list(out_tensor.shape)
                        )
                        in_signature = _permute_shape(out_signature, inv_perm)
                        changed |= _update_tensor_shape(
                            inputs[0],
                            in_shape,
                            in_signature,
                        )
                continue

            if op_type == "GATHER" and len(inputs) >= 2 and len(outputs) == 1:
                params_tensor = model_ir.tensors.get(inputs[0], None)
                indices_tensor = model_ir.tensors.get(inputs[1], None)
                if params_tensor is None or indices_tensor is None:
                    continue
                if not _is_fully_known_positive_shape(list(params_tensor.shape)):
                    continue
                params_shape = [int(v) for v in list(params_tensor.shape)]
                params_signature = (
                    [int(v) for v in list(params_tensor.shape_signature)]
                    if params_tensor.shape_signature is not None
                    else list(params_shape)
                )
                indices_shape = [int(v) for v in list(indices_tensor.shape)]
                indices_signature = (
                    [int(v) for v in list(indices_tensor.shape_signature)]
                    if indices_tensor.shape_signature is not None
                    else list(indices_shape)
                )
                axis = int(op.options.get("axis", 0))
                batch_dims = int(op.options.get("batchDims", 0))
                if batch_dims != 0:
                    continue
                rank = len(params_shape)
                if rank <= 0:
                    continue
                if axis < 0:
                    axis += rank
                if axis < 0 or axis >= rank:
                    continue
                out_shape = (
                    [int(v) for v in params_shape[:axis]]
                    + [int(v) for v in indices_shape]
                    + [int(v) for v in params_shape[axis + 1:]]
                )
                out_signature = (
                    [int(v) for v in params_signature[:axis]]
                    + [int(v) for v in indices_signature]
                    + [int(v) for v in params_signature[axis + 1:]]
                )
                if len(out_shape) == 0:
                    out_shape = [1]
                if len(out_signature) == 0:
                    out_signature = [1]
                changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type == "GATHER_ND" and len(inputs) >= 2 and len(outputs) == 1:
                params_tensor = model_ir.tensors.get(inputs[0], None)
                indices_tensor = model_ir.tensors.get(inputs[1], None)
                if params_tensor is None or indices_tensor is None:
                    continue
                if not _is_fully_known_positive_shape(list(params_tensor.shape)):
                    continue
                params_shape = [int(v) for v in list(params_tensor.shape)]
                params_signature = (
                    [int(v) for v in list(params_tensor.shape_signature)]
                    if params_tensor.shape_signature is not None
                    else list(params_shape)
                )
                indices_shape = [int(v) for v in list(indices_tensor.shape)]
                indices_signature = (
                    [int(v) for v in list(indices_tensor.shape_signature)]
                    if indices_tensor.shape_signature is not None
                    else list(indices_shape)
                )
                if len(indices_shape) < 1:
                    continue
                gather_dims = int(indices_shape[-1])
                if len(indices_signature) > 0 and int(indices_signature[-1]) > 0:
                    gather_dims = int(indices_signature[-1])
                if gather_dims <= 0 or gather_dims > len(params_shape):
                    continue
                out_shape = (
                    [int(v) for v in indices_shape[:-1]]
                    + [int(v) for v in params_shape[gather_dims:]]
                )
                out_signature = (
                    [int(v) for v in indices_signature[:-1]]
                    + [int(v) for v in params_signature[gather_dims:]]
                )
                if len(out_shape) == 0:
                    out_shape = [1]
                if len(out_signature) == 0:
                    out_signature = [1]
                changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type in {"BIDIRECTIONAL_SEQUENCE_LSTM", "UNIDIRECTIONAL_SEQUENCE_LSTM"} \
                and len(inputs) >= 1 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                output_tensor = model_ir.tensors.get(outputs[0], None)
                if (
                    input_tensor is None
                    or output_tensor is None
                    or len(list(input_tensor.shape)) != 3
                    or len(list(output_tensor.shape)) != 3
                    or not _is_fully_known_positive_shape(list(input_tensor.shape))
                ):
                    continue
                input_shape = [int(v) for v in list(input_tensor.shape)]
                input_signature = (
                    [int(v) for v in list(input_tensor.shape_signature)]
                    if input_tensor.shape_signature is not None
                    else list(input_shape)
                )
                output_shape = [int(v) for v in list(output_tensor.shape)]
                output_signature_existing = (
                    [int(v) for v in list(output_tensor.shape_signature)]
                    if output_tensor.shape_signature is not None
                    else list(output_shape)
                )
                time_major = bool(op.options.get("timeMajor", True))
                if time_major:
                    inferred_output_shape = [int(input_shape[0]), int(input_shape[1]), int(output_shape[2])]
                    inferred_output_signature = [
                        int(input_signature[0]),
                        int(input_signature[1]),
                        int(output_signature_existing[2]),
                    ]
                else:
                    inferred_output_shape = [int(input_shape[1]), int(input_shape[0]), int(output_shape[2])]
                    inferred_output_signature = [
                        int(input_signature[1]),
                        int(input_signature[0]),
                        int(output_signature_existing[2]),
                    ]
                changed |= _update_tensor_shape(
                    outputs[0],
                    inferred_output_shape,
                    inferred_output_signature,
                )
                continue

            if op_type == "SPLIT" and len(inputs) >= 2 and len(outputs) >= 1:
                axis_tensor = model_ir.tensors.get(inputs[0], None)
                input_tensor = model_ir.tensors.get(inputs[1], None)
                axis_values = _read_const_ints_from_tensor(axis_tensor)
                if (
                    axis_values is None
                    or len(axis_values) == 0
                    or input_tensor is None
                    or not _is_fully_known_positive_shape(list(input_tensor.shape))
                ):
                    continue
                input_shape = [int(v) for v in list(input_tensor.shape)]
                rank = len(input_shape)
                axis = int(axis_values[0])
                if axis < 0:
                    axis += rank
                if axis < 0 or axis >= rank:
                    continue
                num_splits = int(op.options.get("numSplits", len(outputs)))
                if num_splits <= 0 or len(outputs) != num_splits:
                    continue
                if int(input_shape[axis]) % num_splits != 0:
                    continue
                split_dim = int(input_shape[axis] // num_splits)
                input_signature = (
                    [int(v) for v in list(input_tensor.shape_signature)]
                    if input_tensor.shape_signature is not None
                    else list(input_shape)
                )
                split_signature_dim = -1
                if axis < len(input_signature):
                    sig_dim = int(input_signature[axis])
                    if sig_dim > 0 and sig_dim % num_splits == 0:
                        split_signature_dim = int(sig_dim // num_splits)
                for output_name in outputs:
                    out_shape = [int(v) for v in list(input_shape)]
                    out_shape[axis] = int(split_dim)
                    out_signature = [int(v) for v in list(input_signature)]
                    out_signature[axis] = int(split_signature_dim if split_signature_dim > 0 else -1)
                    changed |= _update_tensor_shape(
                        output_name,
                        out_shape,
                        out_signature,
                    )
                continue

            if op_type == "EXPAND_DIMS" and len(inputs) >= 2 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                axis_tensor = model_ir.tensors.get(inputs[1], None)
                axis_values = _read_const_ints_from_tensor(axis_tensor)
                if (
                    input_tensor is None
                    or axis_values is None
                    or len(axis_values) == 0
                    or not _is_fully_known_positive_shape(list(input_tensor.shape))
                ):
                    continue
                input_shape = [int(v) for v in list(input_tensor.shape)]
                input_signature = (
                    [int(v) for v in list(input_tensor.shape_signature)]
                    if input_tensor.shape_signature is not None
                    else list(input_shape)
                )
                out_rank = len(input_shape) + 1
                axis = int(axis_values[0])
                if axis < 0:
                    axis += out_rank
                if axis < 0 or axis >= out_rank:
                    continue
                out_shape = [int(v) for v in list(input_shape)]
                out_signature = [int(v) for v in list(input_signature)]
                out_shape.insert(axis, 1)
                out_signature.insert(axis, 1)
                changed |= _update_tensor_shape(
                    outputs[0],
                    out_shape,
                    out_signature,
                )
                continue

            if op_type in {"ADD", "SUB", "MUL", "DIV", "FLOOR_MOD", "MAXIMUM", "MINIMUM"} and len(inputs) >= 2 and len(outputs) == 1:
                in0 = model_ir.tensors.get(inputs[0], None)
                in1 = model_ir.tensors.get(inputs[1], None)
                shape0 = list(in0.shape) if in0 is not None else None
                shape1 = list(in1.shape) if in1 is not None else None
                sig0 = (
                    list(in0.shape_signature)
                    if in0 is not None and in0.shape_signature is not None
                    else (list(shape0) if shape0 is not None else None)
                )
                sig1 = (
                    list(in1.shape_signature)
                    if in1 is not None and in1.shape_signature is not None
                    else (list(shape1) if shape1 is not None else None)
                )
                out_shape = _broadcast_static_shapes(shape0, shape1)
                out_signature = _broadcast_shape_signatures(sig0, sig1)
                if out_shape is not None:
                    changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type == "BATCH_MATMUL" and len(inputs) >= 2 and len(outputs) == 1:
                in0 = model_ir.tensors.get(inputs[0], None)
                in1 = model_ir.tensors.get(inputs[1], None)
                shape0 = list(in0.shape) if in0 is not None else None
                shape1 = list(in1.shape) if in1 is not None else None
                sig0 = (
                    list(in0.shape_signature)
                    if in0 is not None and in0.shape_signature is not None
                    else (list(shape0) if shape0 is not None else None)
                )
                sig1 = (
                    list(in1.shape_signature)
                    if in1 is not None and in1.shape_signature is not None
                    else (list(shape1) if shape1 is not None else None)
                )
                out_shape, out_signature = _infer_batch_matmul_output_shape_and_signature(
                    shape_a=shape0,
                    shape_b=shape1,
                    signature_a=sig0,
                    signature_b=sig1,
                    adj_x=bool(op.options.get("adjX", False)),
                    adj_y=bool(op.options.get("adjY", False)),
                )
                if out_shape is not None:
                    changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type == "CONCATENATION" and len(inputs) >= 1 and len(outputs) == 1:
                axis = op.options.get("axis", None)
                if axis is None:
                    continue
                in_shapes: List[List[int]] = []
                in_signatures: List[List[int]] = []
                ranks: List[int] = []
                valid = True
                for input_name in inputs:
                    t = model_ir.tensors.get(input_name, None)
                    if t is None or not _is_fully_known_positive_shape(t.shape):
                        valid = False
                        break
                    shape = [int(v) for v in list(t.shape)]
                    in_shapes.append(shape)
                    in_signatures.append(
                        [int(v) for v in list(t.shape_signature)]
                        if t.shape_signature is not None
                        else list(shape)
                    )
                    ranks.append(len(shape))
                if not valid or len(in_shapes) == 0 or len(set(ranks)) != 1:
                    continue
                rank = int(ranks[0])
                axis_new = int(axis)
                if axis_new < 0:
                    axis_new += rank
                if axis_new < 0 or axis_new >= rank:
                    continue
                out_shape = list(in_shapes[0])
                compatible = True
                for shape in in_shapes[1:]:
                    for dim_idx in range(rank):
                        if dim_idx == axis_new:
                            continue
                        if int(shape[dim_idx]) != int(out_shape[dim_idx]):
                            compatible = False
                            break
                    if not compatible:
                        break
                    out_shape[axis_new] += int(shape[axis_new])
                if compatible:
                    out_signature = [int(v) for v in list(out_shape)]
                    if len(in_signatures) == len(in_shapes):
                        for dim_idx in range(rank):
                            dim_values = [int(sig[dim_idx]) for sig in in_signatures]
                            if dim_idx == axis_new:
                                if any(int(v) < 0 for v in dim_values):
                                    out_signature[dim_idx] = -1
                                else:
                                    out_signature[dim_idx] = int(sum(int(v) for v in dim_values))
                            else:
                                if any(int(v) < 0 for v in dim_values):
                                    out_signature[dim_idx] = -1
                    changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type == "RESHAPE" and len(inputs) >= 1 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                if input_tensor is None:
                    continue
                input_signature = (
                    list(input_tensor.shape_signature)
                    if input_tensor.shape_signature is not None
                    else list(input_tensor.shape)
                )
                raw_new_shape = op.options.get("newShape", [])
                try:
                    new_shape = [int(v) for v in np.asarray(raw_new_shape).reshape(-1).tolist()]
                except Exception:
                    new_shape = []
                resolved = _resolve_reshape_new_shape_from_static_input(
                    new_shape=new_shape,
                    input_signature=input_signature,
                    allow_zero=(
                        bool(op.options.get("allowZero"))
                        if "allowZero" in op.options
                        else None
                    ),
                )
                if resolved is not None and _is_fully_known_positive_shape(resolved):
                    changed |= _update_tensor_shape(outputs[0], resolved)
                continue

            if op_type == "SQUEEZE" and len(inputs) >= 1 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                if input_tensor is None or not _is_fully_known_positive_shape(input_tensor.shape):
                    continue
                raw_axes = op.options.get("squeezeDims", [])
                squeeze_axes = _parse_axes_option(raw_axes)
                input_signature = (
                    list(input_tensor.shape_signature)
                    if input_tensor.shape_signature is not None
                    else list(input_tensor.shape)
                )
                out_shape, out_signature = _infer_squeeze_output_shape_and_signature(
                    input_shape=list(input_tensor.shape),
                    input_signature=input_signature,
                    squeeze_axes=squeeze_axes,
                )
                if out_shape is None or not _is_fully_known_positive_shape(out_shape):
                    continue
                changed |= _update_tensor_shape(
                    outputs[0],
                    out_shape,
                    out_signature,
                )
                continue

            if op_type == "MEAN" and len(inputs) >= 2 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                axes_tensor = model_ir.tensors.get(inputs[1], None)
                if input_tensor is None or not _is_fully_known_positive_shape(input_tensor.shape):
                    continue
                axes_vals = _read_const_ints_from_tensor(axes_tensor)
                keep_dims = bool(op.options.get("keepDims", False))
                input_signature = (
                    list(input_tensor.shape_signature)
                    if input_tensor.shape_signature is not None
                    else list(input_tensor.shape)
                )
                out_shape, out_signature = _infer_reduce_output_shape_and_signature(
                    input_shape=list(input_tensor.shape),
                    input_signature=input_signature,
                    axes=axes_vals,
                    keep_dims=keep_dims,
                )
                if out_shape is None or not _is_fully_known_positive_shape(out_shape):
                    continue
                changed |= _update_tensor_shape(
                    outputs[0],
                    out_shape,
                    out_signature,
                )
                continue

            if op_type == "SLICE" and len(inputs) >= 3 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                begin_tensor = model_ir.tensors.get(inputs[1], None)
                size_tensor = model_ir.tensors.get(inputs[2], None)
                if input_tensor is None:
                    continue
                input_signature = (
                    list(input_tensor.shape_signature)
                    if input_tensor.shape_signature is not None
                    else list(input_tensor.shape)
                )
                has_dynamic_input_dim = any(int(v) < 0 for v in input_signature)
                begin_vals = _read_const_ints_from_tensor(begin_tensor)
                size_vals = _read_const_ints_from_tensor(size_tensor)
                out_shape, resolved_begin, resolved_size = _infer_slice_output_shape_and_resolved_params(
                    input_shape=list(input_tensor.shape),
                    begin_vals=begin_vals,
                    size_vals=size_vals,
                )
                if out_shape is None or resolved_begin is None or resolved_size is None:
                    continue
                out_signature = _infer_slice_output_signature(
                    input_shape=list(input_tensor.shape),
                    input_signature=input_signature,
                    begin_vals=begin_vals,
                    size_vals=size_vals,
                )
                changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                # Keep runtime-driven SLICE semantics when input dimensions are dynamic.
                # Rewriting `size=-1` with placeholder static dims (e.g. 1) can collapse
                # dynamic axes and change model outputs.
                if not has_dynamic_input_dim and not bool(op.options.get("preserveDynamicShape", False)):
                    changed |= _write_const_ints_to_tensor(begin_tensor, resolved_begin)
                    changed |= _write_const_ints_to_tensor(size_tensor, resolved_size)
                continue

            if op_type in {"PAD", "MIRROR_PAD"} and len(inputs) >= 2 and len(outputs) == 1:
                input_tensor = model_ir.tensors.get(inputs[0], None)
                pads_tensor = model_ir.tensors.get(inputs[1], None)
                if (
                    input_tensor is None
                    or pads_tensor is None
                    or not _is_fully_known_positive_shape(input_tensor.shape)
                ):
                    continue
                in_shape = [int(v) for v in list(input_tensor.shape)]
                rank = len(in_shape)
                pads_vals = _read_const_ints_from_tensor(pads_tensor)
                if pads_vals is None or len(pads_vals) != int(rank * 2):
                    continue
                pads_shape = (
                    [int(v) for v in list(pads_tensor.shape)]
                    if pads_tensor.shape is not None
                    else []
                )

                pad_pairs: List[Tuple[int, int]] = []
                if len(pads_shape) == 2 and int(pads_shape[0]) == int(rank) and int(pads_shape[1]) == 2:
                    for axis in range(rank):
                        before = int(pads_vals[int(axis * 2)])
                        after = int(pads_vals[int(axis * 2 + 1)])
                        pad_pairs.append((before, after))
                elif len(pads_shape) == 2 and int(pads_shape[0]) == 2 and int(pads_shape[1]) == int(rank):
                    for axis in range(rank):
                        before = int(pads_vals[int(axis)])
                        after = int(pads_vals[int(rank + axis)])
                        pad_pairs.append((before, after))
                else:
                    for axis in range(rank):
                        before = int(pads_vals[int(axis * 2)])
                        after = int(pads_vals[int(axis * 2 + 1)])
                        pad_pairs.append((before, after))

                if any(int(before) < 0 or int(after) < 0 for before, after in pad_pairs):
                    continue

                out_shape: List[int] = []
                valid_out = True
                for axis in range(rank):
                    before, after = pad_pairs[axis]
                    dim = int(in_shape[axis]) + int(before) + int(after)
                    if int(dim) <= 0:
                        valid_out = False
                        break
                    out_shape.append(int(dim))
                if not valid_out:
                    continue

                input_signature = (
                    list(input_tensor.shape_signature)
                    if input_tensor.shape_signature is not None
                    else list(in_shape)
                )
                out_signature: List[int] = []
                for axis in range(rank):
                    sig_dim = int(input_signature[axis]) if axis < len(input_signature) else int(in_shape[axis])
                    if int(sig_dim) < 0:
                        out_signature.append(-1)
                    else:
                        out_signature.append(int(out_shape[axis]))

                changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type in {"CONV_2D", "DEPTHWISE_CONV_2D"} and len(inputs) >= 2 and len(outputs) == 1:
                in_tensor = model_ir.tensors.get(inputs[0], None)
                filter_tensor = model_ir.tensors.get(inputs[1], None)
                out_tensor = model_ir.tensors.get(outputs[0], None)
                if (
                    in_tensor is None
                    or filter_tensor is None
                    or not _is_fully_known_positive_shape(in_tensor.shape)
                    or not _is_fully_known_positive_shape(filter_tensor.shape)
                ):
                    continue
                in_shape = [int(v) for v in list(in_tensor.shape)]
                filter_shape = [int(v) for v in list(filter_tensor.shape)]
                if len(in_shape) != 4 or len(filter_shape) != 4:
                    continue
                padding = str(op.options.get("padding", "SAME"))
                stride_h = int(op.options.get("strideH", 1))
                stride_w = int(op.options.get("strideW", 1))
                dilation_h = int(op.options.get("dilationHFactor", 1))
                dilation_w = int(op.options.get("dilationWFactor", 1))
                kernel_h = int(filter_shape[1])
                kernel_w = int(filter_shape[2])
                out_h = _infer_conv_out_dim(in_shape[1], kernel_h, stride_h, dilation_h, padding)
                out_w = _infer_conv_out_dim(in_shape[2], kernel_w, stride_w, dilation_w, padding)
                if out_h is None or out_w is None or int(out_h) <= 0 or int(out_w) <= 0:
                    continue
                if op_type == "CONV_2D":
                    out_c = int(filter_shape[0])
                else:
                    # TFLite depthwise filter layout: [1, KH, KW, OC]
                    out_c = int(filter_shape[3])
                out_shape = [int(in_shape[0]), int(out_h), int(out_w), int(out_c)]
                input_signature = (
                    list(in_tensor.shape_signature)
                    if in_tensor.shape_signature is not None
                    else list(in_shape)
                )
                existing_out_signature = (
                    list(out_tensor.shape_signature)
                    if out_tensor is not None and out_tensor.shape_signature is not None
                    else None
                )
                out_signature = _infer_rank4_signature_from_input(
                    input_signature=input_signature,
                    output_shape=out_shape,
                    existing_output_signature=existing_out_signature,
                    propagate_channel=False,
                )
                changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type in {"AVERAGE_POOL_2D", "MAX_POOL_2D"} and len(inputs) >= 1 and len(outputs) == 1:
                in_tensor = model_ir.tensors.get(inputs[0], None)
                out_tensor = model_ir.tensors.get(outputs[0], None)
                if in_tensor is None or not _is_fully_known_positive_shape(in_tensor.shape):
                    continue
                in_shape = [int(v) for v in list(in_tensor.shape)]
                if len(in_shape) != 4:
                    continue

                padding = str(op.options.get("padding", "SAME")).upper()
                stride_h = int(op.options.get("strideH", 1))
                stride_w = int(op.options.get("strideW", 1))
                filter_h = int(op.options.get("filterHeight", 1))
                filter_w = int(op.options.get("filterWidth", 1))

                out_h = _infer_conv_out_dim(in_shape[1], filter_h, stride_h, 1, padding)
                out_w = _infer_conv_out_dim(in_shape[2], filter_w, stride_w, 1, padding)

                # GlobalAveragePool lowering can become stale after aggressive transpose/layout
                # rewrites. Recover invalid VALID+stride=1 average-pool metadata by snapping
                # pool kernel to the current input spatial size.
                if (
                    op_type == "AVERAGE_POOL_2D"
                    and (out_h is None or out_w is None or int(out_h) <= 0 or int(out_w) <= 0)
                    and padding == "VALID"
                    and int(stride_h) == 1
                    and int(stride_w) == 1
                ):
                    if int(filter_h) > int(in_shape[1]) or int(filter_w) > int(in_shape[2]):
                        filter_h = int(in_shape[1])
                        filter_w = int(in_shape[2])
                        op.options["filterHeight"] = int(filter_h)
                        op.options["filterWidth"] = int(filter_w)
                        out_h = _infer_conv_out_dim(in_shape[1], filter_h, stride_h, 1, padding)
                        out_w = _infer_conv_out_dim(in_shape[2], filter_w, stride_w, 1, padding)

                if out_h is None or out_w is None or int(out_h) <= 0 or int(out_w) <= 0:
                    continue
                out_shape = [int(in_shape[0]), int(out_h), int(out_w), int(in_shape[3])]
                input_signature = (
                    list(in_tensor.shape_signature)
                    if in_tensor.shape_signature is not None
                    else list(in_shape)
                )
                existing_out_signature = (
                    list(out_tensor.shape_signature)
                    if out_tensor is not None and out_tensor.shape_signature is not None
                    else None
                )
                out_signature = _infer_rank4_signature_from_input(
                    input_signature=input_signature,
                    output_shape=out_shape,
                    existing_output_signature=existing_out_signature,
                    propagate_channel=True,
                )
                changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

            if op_type in {"RESIZE_BILINEAR", "RESIZE_NEAREST_NEIGHBOR"} and len(inputs) >= 2 and len(outputs) == 1:
                in_tensor = model_ir.tensors.get(inputs[0], None)
                size_tensor = model_ir.tensors.get(inputs[1], None)
                out_tensor = model_ir.tensors.get(outputs[0], None)
                if in_tensor is None or not _is_fully_known_positive_shape(in_tensor.shape):
                    continue
                in_shape = [int(v) for v in list(in_tensor.shape)]
                if len(in_shape) != 4:
                    continue

                out_h = None
                out_w = None
                size_source = "unknown"
                size_vals = _read_const_ints_from_tensor(size_tensor)
                size_tensor_is_const = bool(size_tensor is not None and size_tensor.data is not None)
                onnx_sizes_hw = op.options.get("onnxSizesHW", None)
                if isinstance(onnx_sizes_hw, (list, tuple)) and len(onnx_sizes_hw) >= 2:
                    try:
                        out_h = int(onnx_sizes_hw[0])
                        out_w = int(onnx_sizes_hw[1])
                        size_source = "onnx_sizes"
                    except Exception:
                        out_h = None
                        out_w = None
                        size_source = "unknown"
                if out_h is None or out_w is None:
                    onnx_scales_hw = op.options.get("onnxScalesHW", None)
                    if isinstance(onnx_scales_hw, (list, tuple)) and len(onnx_scales_hw) >= 2:
                        try:
                            out_h = int(round(float(in_shape[1]) * float(onnx_scales_hw[0])))
                            out_w = int(round(float(in_shape[2]) * float(onnx_scales_hw[1])))
                            size_source = "onnx_scales"
                        except Exception:
                            out_h = None
                            out_w = None
                            size_source = "unknown"
                if out_h is None or out_w is None:
                    if size_vals is None or len(size_vals) < 2:
                        continue
                    out_h = int(size_vals[0])
                    out_w = int(size_vals[1])
                    size_source = "const_size"
                if out_h <= 0 or out_w <= 0:
                    continue
                # Synchronize resize-size constants with ONNX-derived hints so downstream
                # prepare-time shape inference follows the reconciled NHWC metadata.
                if size_tensor_is_const and size_source in {"onnx_sizes", "onnx_scales"}:
                    changed |= _write_const_ints_to_tensor(size_tensor, [int(out_h), int(out_w)])
                out_shape = [int(in_shape[0]), int(out_h), int(out_w), int(in_shape[3])]
                input_signature = (
                    list(in_tensor.shape_signature)
                    if in_tensor.shape_signature is not None
                    else list(in_shape)
                )
                existing_out_signature = (
                    list(out_tensor.shape_signature)
                    if out_tensor is not None and out_tensor.shape_signature is not None
                    else None
                )
                out_signature = _infer_rank4_signature_from_input(
                    input_signature=input_signature,
                    output_shape=out_shape,
                    existing_output_signature=existing_out_signature,
                    propagate_channel=True,
                )
                if len(out_signature) == 4 and len(input_signature) == 4 and size_source == "onnx_scales":
                    if int(input_signature[1]) < 0:
                        out_signature[1] = -1
                    if int(input_signature[2]) < 0:
                        out_signature[2] = -1
                changed |= _update_tensor_shape(outputs[0], out_shape, out_signature)
                continue

        if not changed:
            break

    return {"reconciled_static_tensor_shapes": int(updated_tensors)}


def _optimize_transpose_quant_dequant_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose-quantize/dequantize-transpose bridges when both transposes cancel.

    Target patterns:
      X --Transpose(P)--> A --QUANTIZE--> B --Transpose(inv(P))--> Y
      X --Transpose(P)--> A --DEQUANTIZE--> B --Transpose(inv(P))--> Y

    This is safe for per-tensor quantization only.
    """
    removed_bridge_pairs = 0
    rewritten_add_qdq_residual_bridges = 0
    rewritten_mixed_add_qdq_residual_bridges = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        # Pattern A:
        #   X -T(P)-> A -Q-> B -DQ-> C -T(invP)-> Y
        # -> X -Q-> B -DQ-> Y
        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            bridge_a = pre_op.outputs[0]
            q_users = consumers.get(bridge_a, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if q_op.inputs[0] != bridge_a:
                continue

            bridge_b = q_op.outputs[0]
            dq_users = consumers.get(bridge_b, [])
            if len(dq_users) != 1:
                continue
            dq_idx = int(dq_users[0])
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if dq_op.inputs[0] != bridge_b:
                continue

            bridge_c = dq_op.outputs[0]
            post_users = consumers.get(bridge_c, [])
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[post_idx]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if post_op.inputs[0] != bridge_c:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_pre is None or perm_post is None:
                continue
            if not _is_inverse_perm(perm_pre, perm_post):
                continue

            q_out_tensor = model_ir.tensors.get(bridge_b, None)
            if q_out_tensor is None or not _is_per_tensor_quantization(q_out_tensor.quantization):
                continue

            if bridge_a in model_ir.outputs or bridge_b in model_ir.outputs or bridge_c in model_ir.outputs:
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=q_op,
                new_inputs=[pre_op.inputs[0]],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=dq_op,
                new_outputs=[post_op.outputs[0]],
            )

            new_dq_out = model_ir.tensors.get(post_op.outputs[0], None)
            old_dq_out = model_ir.tensors.get(bridge_c, None)
            if new_dq_out is not None and old_dq_out is not None:
                new_dq_out.dtype = str(old_dq_out.dtype)

            for remove_idx in sorted([pre_idx, post_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_bridge_pairs += 1
            changed = True
            break

        if changed:
            continue

        # Pattern B:
        #   X -T(P)-> A -(Q|DQ)-> B -T(invP)-> Y
        # -> X -(Q|DQ)-> Y
        for mid_idx, mid_op in enumerate(model_ir.operators):
            if str(mid_op.op_type) not in {"QUANTIZE", "DEQUANTIZE"}:
                continue
            if len(mid_op.inputs) != 1 or len(mid_op.outputs) != 1:
                continue

            bridge_in = mid_op.inputs[0]
            bridge_out = mid_op.outputs[0]

            pre_idx = producers.get(bridge_in, None)
            if pre_idx is None:
                continue
            pre_op = model_ir.operators[pre_idx]
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.outputs) != 1 or len(pre_op.inputs) < 2:
                continue
            if pre_op.outputs[0] != bridge_in:
                continue
            in_users = set(consumers.get(bridge_in, []))
            if int(mid_idx) not in in_users:
                continue
            can_remove_pre = in_users == {int(mid_idx)}

            post_users = [int(v) for v in consumers.get(bridge_out, []) if int(v) != int(mid_idx)]
            if len(post_users) == 0:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            valid_posts = True
            for post_idx in post_users:
                post_op = model_ir.operators[int(post_idx)]
                if (
                    str(post_op.op_type) != "TRANSPOSE"
                    or len(post_op.inputs) < 2
                    or len(post_op.outputs) != 1
                    or post_op.inputs[0] != bridge_out
                ):
                    valid_posts = False
                    break
                perm_post = _read_transpose_perm(model_ir, post_op)
                if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                    valid_posts = False
                    break
                post_indices.append(int(post_idx))
                post_output_names.append(str(post_op.outputs[0]))
            if not valid_posts or len(post_indices) == 0:
                continue

            # Keep visible output names stable.
            if bridge_out in model_ir.outputs:
                continue
            if can_remove_pre and bridge_in in model_ir.outputs:
                continue
            single_post = len(post_indices) == 1
            if (not single_post) and any(
                post_output_name in model_ir.outputs for post_output_name in post_output_names
            ):
                continue

            pre_input_name = pre_op.inputs[0]
            representative_post_output_name = post_output_names[0]

            if str(mid_op.op_type) == "QUANTIZE":
                bridge_out_tensor = model_ir.tensors.get(bridge_out, None)
                if bridge_out_tensor is None:
                    continue
                if not _is_per_tensor_quantization(bridge_out_tensor.quantization):
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mid_op,
                    new_inputs=[pre_input_name],
                )
                if single_post:
                    post_output_name = representative_post_output_name
                    _set_operator_outputs(
                        model_ir=model_ir,
                        op=mid_op,
                        new_outputs=[post_output_name],
                    )
                    post_output_tensor = model_ir.tensors.get(post_output_name, None)
                    if post_output_tensor is not None:
                        post_output_tensor.dtype = str(bridge_out_tensor.dtype)
                        post_output_tensor.quantization = _clone_quantization(
                            bridge_out_tensor.quantization
                        )
                else:
                    rep_post_tensor = model_ir.tensors.get(representative_post_output_name, None)
                    if rep_post_tensor is not None:
                        bridge_out_tensor.shape = list(rep_post_tensor.shape)
                        bridge_out_tensor.shape_signature = (
                            list(rep_post_tensor.shape_signature)
                            if rep_post_tensor.shape_signature is not None
                            else list(rep_post_tensor.shape)
                        )
                        bridge_out_tensor.dtype = str(rep_post_tensor.dtype)
                    bridge_out_tensor.quantization = _clone_quantization(
                        bridge_out_tensor.quantization
                    )
            else:
                bridge_in_tensor = model_ir.tensors.get(bridge_in, None)
                if bridge_in_tensor is None:
                    continue
                if not _is_per_tensor_quantization(bridge_in_tensor.quantization):
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mid_op,
                    new_inputs=[pre_input_name],
                )
                if single_post:
                    post_output_name = representative_post_output_name
                    _set_operator_outputs(
                        model_ir=model_ir,
                        op=mid_op,
                        new_outputs=[post_output_name],
                    )
                    pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
                    if pre_input_tensor is not None and pre_input_tensor.quantization is None:
                        pre_input_tensor.quantization = _clone_quantization(
                            bridge_in_tensor.quantization
                        )
                    post_output_tensor = model_ir.tensors.get(post_output_name, None)
                    bridge_out_tensor = model_ir.tensors.get(bridge_out, None)
                    if post_output_tensor is not None and bridge_out_tensor is not None:
                        post_output_tensor.dtype = str(bridge_out_tensor.dtype)
                else:
                    pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
                    if pre_input_tensor is not None and pre_input_tensor.quantization is None:
                        pre_input_tensor.quantization = _clone_quantization(
                            bridge_in_tensor.quantization
                        )
                    bridge_out_tensor = model_ir.tensors.get(bridge_out, None)
                    rep_post_tensor = model_ir.tensors.get(representative_post_output_name, None)
                    if bridge_out_tensor is not None and rep_post_tensor is not None:
                        bridge_out_tensor.shape = list(rep_post_tensor.shape)
                        bridge_out_tensor.shape_signature = (
                            list(rep_post_tensor.shape_signature)
                            if rep_post_tensor.shape_signature is not None
                            else list(rep_post_tensor.shape)
                        )
                        bridge_out_tensor.dtype = str(rep_post_tensor.dtype)

            if not single_post:
                for post_output_name in post_output_names:
                    _replace_tensor_inputs(model_ir, post_output_name, bridge_out)

            remove_indices = list(post_indices)
            if can_remove_pre:
                remove_indices.append(pre_idx)
            for remove_idx in sorted(remove_indices, reverse=True):
                del model_ir.operators[remove_idx]
            removed_bridge_pairs += int(1 if single_post else max(1, len(post_indices)))
            changed = True
            break

        if changed:
            continue

        # Pattern C:
        #   a_nhwc -T(n2c)-> a_nchw -Q-> aq -DQ-> adq -(optional T(c2n))*->
        #   b_nhwc -T(n2c)-> b_nchw -Q-> bq -DQ-> bdq
        #   ADD(adq, bdq) -> sum_nchw -Q-> sum_q -DQ-> sum_dq -T(c2n)-> sum_nhwc
        # -> Remove the NCHW adapters by keeping Q/DQ and ADD in NHWC.
        #
        # Notes:
        # - This intentionally targets strict residual branches where ADD inputs are
        #   Q/DQ-dequantized tensors produced from pre-transpose wrappers.
        # - Side fanout from branch DQ outputs is allowed only via inverse post-transpose.
        model_outputs = set(str(v) for v in model_ir.outputs)
        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue

            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_outputs:
                continue

            branch_specs: List[Dict[str, Any]] = []
            common_perm_post: Optional[List[int]] = None
            valid_add_branches = True

            for add_input_name in [str(v) for v in list(add_op.inputs)]:
                if add_input_name in model_outputs:
                    valid_add_branches = False
                    break

                dq_idx = producers.get(add_input_name, None)
                if dq_idx is None:
                    valid_add_branches = False
                    break
                dq_op = model_ir.operators[int(dq_idx)]
                if (
                    str(dq_op.op_type) != "DEQUANTIZE"
                    or len(dq_op.inputs) != 1
                    or len(dq_op.outputs) != 1
                    or str(dq_op.outputs[0]) != add_input_name
                ):
                    valid_add_branches = False
                    break

                q_out_name = str(dq_op.inputs[0])
                q_idx = producers.get(q_out_name, None)
                if q_idx is None:
                    valid_add_branches = False
                    break
                q_op = model_ir.operators[int(q_idx)]
                if (
                    str(q_op.op_type) != "QUANTIZE"
                    or len(q_op.inputs) != 1
                    or len(q_op.outputs) != 1
                    or str(q_op.outputs[0]) != q_out_name
                ):
                    valid_add_branches = False
                    break

                q_out_tensor = model_ir.tensors.get(q_out_name, None)
                if q_out_tensor is None or not _is_per_tensor_quantization(q_out_tensor.quantization):
                    valid_add_branches = False
                    break

                pre_in_name = str(q_op.inputs[0])
                pre_idx = producers.get(pre_in_name, None)
                if pre_idx is None:
                    valid_add_branches = False
                    break
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != pre_in_name
                ):
                    valid_add_branches = False
                    break

                perm_pre = _read_transpose_perm(model_ir, pre_op)
                if perm_pre is None:
                    valid_add_branches = False
                    break
                perm_post_expected = _invert_perm(perm_pre)
                if perm_post_expected is None:
                    valid_add_branches = False
                    break
                if common_perm_post is None:
                    common_perm_post = [int(v) for v in list(perm_post_expected)]
                elif list(common_perm_post) != list(perm_post_expected):
                    valid_add_branches = False
                    break

                pre_output_name = str(pre_op.outputs[0])
                pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
                can_remove_pre = set(pre_users) == {int(q_idx)}

                branch_post_indices: List[int] = []
                branch_post_output_names: List[str] = []
                branch_other_users = [
                    int(v)
                    for v in consumers.get(add_input_name, [])
                    if int(v) != int(add_idx)
                ]
                for user_idx in branch_other_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) != "TRANSPOSE"
                        or len(user_op.inputs) < 2
                        or len(user_op.outputs) != 1
                        or str(user_op.inputs[0]) != add_input_name
                    ):
                        valid_add_branches = False
                        break
                    user_perm = _read_transpose_perm(model_ir, user_op)
                    if user_perm is None or list(user_perm) != list(perm_post_expected):
                        valid_add_branches = False
                        break
                    branch_post_out_name = str(user_op.outputs[0])
                    if branch_post_out_name in model_outputs:
                        valid_add_branches = False
                        break
                    branch_post_indices.append(int(user_idx))
                    branch_post_output_names.append(branch_post_out_name)
                if not valid_add_branches:
                    break

                branch_specs.append(
                    {
                        "pre_idx": int(pre_idx),
                        "q_idx": int(q_idx),
                        "dq_idx": int(dq_idx),
                        "pre_input_name": str(pre_op.inputs[0]),
                        "q_out_name": str(q_out_name),
                        "dq_out_name": str(add_input_name),
                        "perm_post": [int(v) for v in list(perm_post_expected)],
                        "post_indices": [int(v) for v in branch_post_indices],
                        "post_output_names": [str(v) for v in branch_post_output_names],
                        "can_remove_pre": bool(can_remove_pre),
                    }
                )

            if not valid_add_branches or len(branch_specs) != 2 or common_perm_post is None:
                continue

            add_users = [
                int(v)
                for v in consumers.get(add_out_name, [])
                if int(v) != int(add_idx)
            ]
            if len(add_users) != 1:
                continue

            out_q_idx = int(add_users[0])
            out_q_op = model_ir.operators[int(out_q_idx)]
            if str(out_q_op.op_type) != "QUANTIZE" or len(out_q_op.inputs) != 1 or len(out_q_op.outputs) != 1:
                continue
            if str(out_q_op.inputs[0]) != add_out_name:
                continue

            out_q_name = str(out_q_op.outputs[0])
            out_q_tensor = model_ir.tensors.get(out_q_name, None)
            if out_q_tensor is None or not _is_per_tensor_quantization(out_q_tensor.quantization):
                continue
            if out_q_name in model_outputs:
                continue

            out_q_users = [int(v) for v in consumers.get(out_q_name, []) if int(v) != int(out_q_idx)]
            if len(out_q_users) != 1:
                continue

            out_dq_idx = int(out_q_users[0])
            out_dq_op = model_ir.operators[int(out_dq_idx)]
            if (
                str(out_dq_op.op_type) != "DEQUANTIZE"
                or len(out_dq_op.inputs) != 1
                or len(out_dq_op.outputs) != 1
                or str(out_dq_op.inputs[0]) != out_q_name
            ):
                continue

            out_dq_name = str(out_dq_op.outputs[0])
            if out_dq_name in model_outputs:
                continue

            out_post_indices: List[int] = []
            out_post_output_names: List[str] = []
            out_legacy_user_indices: List[int] = []
            invalid_output_tail = False
            out_dq_users = [
                int(v)
                for v in consumers.get(out_dq_name, [])
                if int(v) != int(out_dq_idx)
            ]
            for user_idx in out_dq_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == out_dq_name
                ):
                    user_perm = _read_transpose_perm(model_ir, user_op)
                    if user_perm is not None and list(user_perm) == list(common_perm_post):
                        out_post_name = str(user_op.outputs[0])
                        if out_post_name in model_outputs:
                            invalid_output_tail = True
                            break
                        out_post_indices.append(int(user_idx))
                        out_post_output_names.append(out_post_name)
                        continue
                out_legacy_user_indices.append(int(user_idx))

            if invalid_output_tail:
                continue
            if len(out_legacy_user_indices) > 0 and len(out_post_indices) == 0:
                continue

            remove_indices: set[int] = set()
            removed_transposes_local = 0
            out_dq_tensor = model_ir.tensors.get(out_dq_name, None)
            out_dq_shape_before_permute = (
                [int(v) for v in list(out_dq_tensor.shape)]
                if out_dq_tensor is not None and out_dq_tensor.shape is not None
                else None
            )
            out_dq_signature_before_permute = (
                [int(v) for v in list(out_dq_tensor.shape_signature)]
                if out_dq_tensor is not None and out_dq_tensor.shape_signature is not None
                else (
                    [int(v) for v in list(out_dq_tensor.shape)]
                    if out_dq_tensor is not None and out_dq_tensor.shape is not None
                    else None
                )
            )

            for branch_spec in branch_specs:
                q_op = model_ir.operators[int(branch_spec["q_idx"])]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=q_op,
                    new_inputs=[str(branch_spec["pre_input_name"])],
                )

                q_tensor = model_ir.tensors.get(str(branch_spec["q_out_name"]), None)
                dq_tensor = model_ir.tensors.get(str(branch_spec["dq_out_name"]), None)
                post_output_names = [str(v) for v in list(branch_spec["post_output_names"])]
                if len(post_output_names) > 0:
                    representative_post_tensor = model_ir.tensors.get(post_output_names[0], None)
                    if dq_tensor is not None and representative_post_tensor is not None:
                        dq_tensor.shape = [int(v) for v in list(representative_post_tensor.shape)]
                        dq_tensor.shape_signature = (
                            [int(v) for v in list(representative_post_tensor.shape_signature)]
                            if representative_post_tensor.shape_signature is not None
                            else [int(v) for v in list(representative_post_tensor.shape)]
                        )
                    if q_tensor is not None and dq_tensor is not None:
                        q_tensor.shape = [int(v) for v in list(dq_tensor.shape)]
                        q_tensor.shape_signature = (
                            [int(v) for v in list(dq_tensor.shape_signature)]
                            if dq_tensor.shape_signature is not None
                            else [int(v) for v in list(dq_tensor.shape)]
                        )
                else:
                    _permute_tensor_metadata_if_rank_matches(
                        q_tensor,
                        [int(v) for v in list(branch_spec["perm_post"])],
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        dq_tensor,
                        [int(v) for v in list(branch_spec["perm_post"])],
                    )

                for post_output_name in post_output_names:
                    _replace_tensor_inputs(model_ir, post_output_name, str(branch_spec["dq_out_name"]))
                for post_idx in [int(v) for v in list(branch_spec["post_indices"])]:
                    remove_indices.add(int(post_idx))
                    removed_transposes_local += 1

                if bool(branch_spec["can_remove_pre"]):
                    remove_indices.add(int(branch_spec["pre_idx"]))
                    removed_transposes_local += 1

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add_out_name, None),
                [int(v) for v in list(common_perm_post)],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(out_q_name, None),
                [int(v) for v in list(common_perm_post)],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(out_dq_name, None),
                [int(v) for v in list(common_perm_post)],
            )

            keep_post_idx: Optional[int] = None
            keep_post_output_name: Optional[str] = None
            perm_nhwc_to_nchw = _invert_perm(list(common_perm_post))
            if len(out_legacy_user_indices) > 0:
                keep_post_idx = int(out_post_indices[0])
                keep_post_op = model_ir.operators[int(keep_post_idx)]
                keep_post_output_name = str(keep_post_op.outputs[0])
                if perm_nhwc_to_nchw is None:
                    keep_post_idx = None
                    keep_post_output_name = None
                else:
                    keep_perm_name = str(keep_post_op.inputs[1])
                    keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                    if keep_perm_tensor is not None:
                        keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=keep_post_op,
                        new_inputs=[out_dq_name, keep_perm_name],
                    )
                    _set_operator_outputs(
                        model_ir=model_ir,
                        op=keep_post_op,
                        new_outputs=[keep_post_output_name],
                    )
                    if keep_post_output_name is not None:
                        keep_post_tensor = model_ir.tensors.get(keep_post_output_name, None)
                        if (
                            keep_post_tensor is not None
                            and out_dq_shape_before_permute is not None
                            and out_dq_signature_before_permute is not None
                        ):
                            keep_post_tensor.shape = [int(v) for v in list(out_dq_shape_before_permute)]
                            keep_post_tensor.shape_signature = [
                                int(v) for v in list(out_dq_signature_before_permute)
                            ]
            if len(out_legacy_user_indices) > 0 and keep_post_output_name is None:
                continue

            for out_post_output_name in out_post_output_names:
                _replace_tensor_inputs(model_ir, out_post_output_name, out_dq_name)
            for legacy_user_idx in out_legacy_user_indices:
                if keep_post_output_name is None:
                    continue
                legacy_user_op = model_ir.operators[int(legacy_user_idx)]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=legacy_user_op,
                    new_inputs=[
                        keep_post_output_name if str(inp) == out_dq_name else str(inp)
                        for inp in list(legacy_user_op.inputs)
                    ],
                )
            for out_post_idx in out_post_indices:
                if keep_post_idx is not None and int(out_post_idx) == int(keep_post_idx):
                    continue
                remove_indices.add(int(out_post_idx))
                removed_transposes_local += 1

            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            removed_bridge_pairs += int(max(1, removed_transposes_local // 2))
            rewritten_add_qdq_residual_bridges += 1
            changed = True
            break

        if changed:
            continue

        # Pattern D:
        #   skip_nhwc --T(P)------------------------------> skip_nchw
        #   proj_nhwc --T(P)--> QUANTIZE -> DEQUANTIZE --> proj_nchw
        #   ADD(proj_nchw, skip_nchw) -> y_nchw -> QUANTIZE -> DEQUANTIZE -> T(invP) -> y_nhwc
        # -> Keep Q/DQ and ADD in NHWC by bypassing skip/proj pre-transposes and final post-transpose.
        for post_idx, post_op in enumerate(model_ir.operators):
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            post_input_name = str(post_op.inputs[0])
            post_output_name = str(post_op.outputs[0])
            if post_input_name in model_ir.outputs:
                continue

            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None:
                continue
            perm_pre_expected = _invert_perm(perm_post)
            if perm_pre_expected is None:
                continue

            dq_out_name = post_input_name
            dq_idx = producers.get(dq_out_name, None)
            if dq_idx is None:
                continue
            dq_op = model_ir.operators[int(dq_idx)]
            if (
                str(dq_op.op_type) != "DEQUANTIZE"
                or len(dq_op.inputs) != 1
                or len(dq_op.outputs) != 1
                or str(dq_op.outputs[0]) != dq_out_name
            ):
                continue

            dq_out_users = [int(v) for v in consumers.get(dq_out_name, []) if int(v) != int(dq_idx)]
            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_user_indices: List[int] = []
            valid_post_fanout = True
            for user_idx in dq_out_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == dq_out_name
                ):
                    user_perm = _read_transpose_perm(model_ir, user_op)
                    if user_perm is not None and list(user_perm) == list(perm_post):
                        post_indices.append(int(user_idx))
                        post_output_names.append(str(user_op.outputs[0]))
                        continue
                legacy_user_indices.append(int(user_idx))
            if not valid_post_fanout:
                continue
            if int(post_idx) not in set(int(v) for v in post_indices):
                continue
            if len(post_indices) == 0:
                continue

            out_q_name = str(dq_op.inputs[0])
            out_q_idx = producers.get(out_q_name, None)
            if out_q_idx is None:
                continue
            out_q_op = model_ir.operators[int(out_q_idx)]
            if (
                str(out_q_op.op_type) != "QUANTIZE"
                or len(out_q_op.inputs) != 1
                or len(out_q_op.outputs) != 1
                or str(out_q_op.outputs[0]) != out_q_name
            ):
                continue

            out_q_tensor = model_ir.tensors.get(out_q_name, None)
            if out_q_tensor is None or not _is_per_tensor_quantization(out_q_tensor.quantization):
                continue
            add_out_name = str(out_q_op.inputs[0])
            if add_out_name in model_ir.outputs:
                continue

            add_idx = producers.get(add_out_name, None)
            if add_idx is None:
                continue
            add_op = model_ir.operators[int(add_idx)]
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue
            if str(add_op.outputs[0]) != add_out_name:
                continue

            proj_branch: Optional[Dict[str, Any]] = None
            skip_branch: Optional[Dict[str, Any]] = None
            valid_inputs = True

            for add_input_name in [str(v) for v in list(add_op.inputs)]:
                add_input_prod_idx = producers.get(add_input_name, None)
                if add_input_prod_idx is None:
                    valid_inputs = False
                    break
                add_input_prod_op = model_ir.operators[int(add_input_prod_idx)]
                add_input_prod_type = str(add_input_prod_op.op_type)

                if add_input_prod_type == "DEQUANTIZE":
                    if (
                        len(add_input_prod_op.inputs) != 1
                        or len(add_input_prod_op.outputs) != 1
                        or str(add_input_prod_op.outputs[0]) != add_input_name
                    ):
                        valid_inputs = False
                        break
                    in_q_name = str(add_input_prod_op.inputs[0])
                    in_q_idx = producers.get(in_q_name, None)
                    if in_q_idx is None:
                        valid_inputs = False
                        break
                    in_q_op = model_ir.operators[int(in_q_idx)]
                    if (
                        str(in_q_op.op_type) != "QUANTIZE"
                        or len(in_q_op.inputs) != 1
                        or len(in_q_op.outputs) != 1
                        or str(in_q_op.outputs[0]) != in_q_name
                    ):
                        valid_inputs = False
                        break
                    in_q_tensor = model_ir.tensors.get(in_q_name, None)
                    if in_q_tensor is None or not _is_per_tensor_quantization(in_q_tensor.quantization):
                        valid_inputs = False
                        break

                    pre_name = str(in_q_op.inputs[0])
                    pre_idx = producers.get(pre_name, None)
                    if pre_idx is None:
                        valid_inputs = False
                        break
                    pre_op = model_ir.operators[int(pre_idx)]
                    if (
                        str(pre_op.op_type) != "TRANSPOSE"
                        or len(pre_op.inputs) < 2
                        or len(pre_op.outputs) != 1
                        or str(pre_op.outputs[0]) != pre_name
                    ):
                        valid_inputs = False
                        break
                    pre_perm = _read_transpose_perm(model_ir, pre_op)
                    if pre_perm is None or list(pre_perm) != list(perm_pre_expected):
                        valid_inputs = False
                        break

                    dq_input_users = [int(v) for v in consumers.get(add_input_name, [])]
                    if set(dq_input_users) != {int(add_idx)}:
                        valid_inputs = False
                        break

                    pre_output_name = str(pre_op.outputs[0])
                    pre_output_users = [int(v) for v in consumers.get(pre_output_name, [])]
                    can_remove_pre = set(pre_output_users) == {int(in_q_idx)}

                    if proj_branch is not None:
                        valid_inputs = False
                        break
                    proj_branch = {
                        "pre_idx": int(pre_idx),
                        "q_idx": int(in_q_idx),
                        "dq_name": str(add_input_name),
                        "pre_input_name": str(pre_op.inputs[0]),
                        "can_remove_pre": bool(can_remove_pre),
                    }
                    continue

                if add_input_prod_type == "TRANSPOSE":
                    if (
                        len(add_input_prod_op.inputs) < 2
                        or len(add_input_prod_op.outputs) != 1
                        or str(add_input_prod_op.outputs[0]) != add_input_name
                    ):
                        valid_inputs = False
                        break
                    pre_perm = _read_transpose_perm(model_ir, add_input_prod_op)
                    if pre_perm is None or list(pre_perm) != list(perm_pre_expected):
                        valid_inputs = False
                        break

                    skip_users = [int(v) for v in consumers.get(add_input_name, [])]
                    if set(skip_users) != {int(add_idx)}:
                        valid_inputs = False
                        break

                    if skip_branch is not None:
                        valid_inputs = False
                        break
                    skip_branch = {
                        "pre_idx": int(add_input_prod_idx),
                        "pre_input_name": str(add_input_prod_op.inputs[0]),
                        "skip_name": str(add_input_name),
                    }
                    continue

                valid_inputs = False
                break

            if (not valid_inputs) or proj_branch is None or skip_branch is None:
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=model_ir.operators[int(proj_branch["q_idx"])],
                new_inputs=[str(proj_branch["pre_input_name"])],
            )

            new_add_inputs = [
                str(skip_branch["pre_input_name"]) if str(v) == str(skip_branch["skip_name"]) else str(v)
                for v in list(add_op.inputs)
            ]
            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=new_add_inputs,
            )

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(proj_branch["dq_name"]), None),
                list(perm_post),
            )
            proj_q_op = model_ir.operators[int(proj_branch["q_idx"])]
            if len(proj_q_op.outputs) == 1:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(proj_q_op.outputs[0]), None),
                    list(perm_post),
                )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add_out_name, None),
                list(perm_post),
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(out_q_name, None),
                list(perm_post),
            )
            canonical_post_idx = int(post_idx)
            canonical_post_output_name = str(post_output_name)

            _set_operator_outputs(
                model_ir=model_ir,
                op=dq_op,
                new_outputs=[canonical_post_output_name],
            )
            new_dq_out_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            old_dq_out_tensor = model_ir.tensors.get(dq_out_name, None)
            if new_dq_out_tensor is not None and old_dq_out_tensor is not None:
                new_dq_out_tensor.dtype = str(old_dq_out_tensor.dtype)

            remove_indices = {int(skip_branch["pre_idx"])}
            if bool(proj_branch["can_remove_pre"]):
                remove_indices.add(int(proj_branch["pre_idx"]))
            if len(legacy_user_indices) > 0:
                keep_post_op = model_ir.operators[int(canonical_post_idx)]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(list(perm_pre_expected), dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[canonical_post_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[dq_out_name],
                )
                for post_output in post_output_names:
                    if str(post_output) == canonical_post_output_name:
                        continue
                    _replace_tensor_inputs(model_ir, str(post_output), canonical_post_output_name)
                for idx_rm in post_indices:
                    if int(idx_rm) == int(canonical_post_idx):
                        continue
                    remove_indices.add(int(idx_rm))
            else:
                for post_output in post_output_names:
                    if str(post_output) == canonical_post_output_name:
                        continue
                    _replace_tensor_inputs(model_ir, str(post_output), canonical_post_output_name)
                for idx_rm in post_indices:
                    remove_indices.add(int(idx_rm))

            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten_mixed_add_qdq_residual_bridges += 1
            removed_bridge_pairs += int(1)
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_transpose_quantize_dequantize_bridges": int(removed_bridge_pairs),
        "rewritten_add_qdq_residual_transpose_bridges": int(rewritten_add_qdq_residual_bridges),
        "rewritten_mixed_add_qdq_residual_transpose_bridges": int(
            rewritten_mixed_add_qdq_residual_bridges
        ),
    }


def _optimize_duplicate_transpose_fanout(model_ir: ModelIR) -> Dict[str, int]:
    """
    Deduplicate fan-out TRANSPOSE nodes with identical input and permutation.

    Target pattern:
      X --TRANSPOSE(P)--> Y0
      X --TRANSPOSE(P)--> Y1
      ...

    Rewritten:
      X --TRANSPOSE(P)--> Y0
      (all uses of Y1, ... are rewired to Y0; duplicate TRANSPOSE nodes removed)
    """
    removed_duplicates = 0

    while True:
        changed = False
        canonical_by_key: Dict[Tuple[str, Tuple[int, ...]], int] = {}

        for op_idx, op in enumerate(model_ir.operators):
            if str(op.op_type) != "TRANSPOSE":
                continue
            if len(op.inputs) < 2 or len(op.outputs) != 1:
                continue

            input_name = str(op.inputs[0])
            output_name = str(op.outputs[0])
            perm = _read_transpose_perm(model_ir, op)
            if perm is None:
                continue

            key = (input_name, tuple(int(v) for v in perm))
            canonical_idx = canonical_by_key.get(key, None)
            if canonical_idx is None:
                canonical_by_key[key] = int(op_idx)
                continue

            if output_name in model_ir.outputs:
                # Preserve user-visible graph output names.
                continue

            canonical_op = model_ir.operators[int(canonical_idx)]
            if len(canonical_op.outputs) != 1:
                continue
            canonical_output = str(canonical_op.outputs[0])
            if canonical_output == output_name:
                continue

            canonical_tensor = model_ir.tensors.get(canonical_output, None)
            duplicate_tensor = model_ir.tensors.get(output_name, None)
            if canonical_tensor is not None and duplicate_tensor is not None:
                if canonical_tensor.shape == [1] and duplicate_tensor.shape != [1]:
                    canonical_tensor.shape = [int(v) for v in list(duplicate_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(duplicate_tensor.shape_signature)]
                        if duplicate_tensor.shape_signature is not None
                        else [int(v) for v in list(duplicate_tensor.shape)]
                    )
                if canonical_tensor.quantization is None and duplicate_tensor.quantization is not None:
                    canonical_tensor.quantization = _clone_quantization(duplicate_tensor.quantization)
                if str(canonical_tensor.dtype) == "FLOAT32" and str(duplicate_tensor.dtype) != "FLOAT32":
                    canonical_tensor.dtype = str(duplicate_tensor.dtype)

            _replace_tensor_inputs(model_ir, output_name, canonical_output)
            del model_ir.operators[int(op_idx)]
            removed_duplicates += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_duplicate_transpose_fanout": int(removed_duplicates),
    }


def _optimize_duplicate_reshape_fanout(model_ir: ModelIR) -> Dict[str, int]:
    """
    Deduplicate fan-out RESHAPE nodes with identical input and target shape.

    Target pattern:
      X --RESHAPE(S)--> Y0
      X --RESHAPE(S)--> Y1
      ...

    Rewritten:
      X --RESHAPE(S)--> Y0
      (all uses of Y1, ... are rewired to Y0; duplicate RESHAPE nodes removed)
    """
    removed_duplicates = 0

    def _read_reshape_target_shape(op: OperatorIR) -> Optional[List[int]]:
        if str(op.op_type) != "RESHAPE":
            return None
        if isinstance(op.options, dict):
            new_shape = op.options.get("newShape", None)
            if isinstance(new_shape, list) and len(new_shape) > 0:
                try:
                    return [int(v) for v in list(new_shape)]
                except Exception:
                    pass
        if len(op.inputs) >= 2:
            shape_tensor = model_ir.tensors.get(str(op.inputs[1]), None)
            shape_values = _read_const_ints_from_tensor(shape_tensor)
            if shape_values is not None and len(shape_values) > 0:
                return [int(v) for v in list(shape_values)]
        return None

    while True:
        changed = False
        canonical_by_key: Dict[Tuple[str, Tuple[int, ...]], int] = {}

        for op_idx, op in enumerate(model_ir.operators):
            if str(op.op_type) != "RESHAPE":
                continue
            if len(op.inputs) < 2 or len(op.outputs) != 1:
                continue

            input_name = str(op.inputs[0])
            output_name = str(op.outputs[0])
            target_shape = _read_reshape_target_shape(op)
            if target_shape is None:
                continue

            key = (input_name, tuple(int(v) for v in list(target_shape)))
            canonical_idx = canonical_by_key.get(key, None)
            if canonical_idx is None:
                canonical_by_key[key] = int(op_idx)
                continue

            if output_name in model_ir.outputs:
                # Preserve user-visible graph output names.
                continue

            canonical_op = model_ir.operators[int(canonical_idx)]
            if len(canonical_op.outputs) != 1:
                continue
            canonical_output = str(canonical_op.outputs[0])
            if canonical_output == output_name:
                continue

            canonical_tensor = model_ir.tensors.get(canonical_output, None)
            duplicate_tensor = model_ir.tensors.get(output_name, None)
            if canonical_tensor is not None and duplicate_tensor is not None:
                if canonical_tensor.shape == [1] and duplicate_tensor.shape != [1]:
                    canonical_tensor.shape = [int(v) for v in list(duplicate_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(duplicate_tensor.shape_signature)]
                        if duplicate_tensor.shape_signature is not None
                        else [int(v) for v in list(duplicate_tensor.shape)]
                    )
                if canonical_tensor.quantization is None and duplicate_tensor.quantization is not None:
                    canonical_tensor.quantization = _clone_quantization(duplicate_tensor.quantization)
                if str(canonical_tensor.dtype) == "FLOAT32" and str(duplicate_tensor.dtype) != "FLOAT32":
                    canonical_tensor.dtype = str(duplicate_tensor.dtype)

            _replace_tensor_inputs(model_ir, output_name, canonical_output)
            del model_ir.operators[int(op_idx)]
            removed_duplicates += 1
            changed = True
            break

        if not changed:
            break

    if removed_duplicates > 0:
        _prune_unused_tensors(model_ir)
    return {
        "removed_duplicate_reshape_fanout": int(removed_duplicates),
    }


def _optimize_transpose_dequant_prelu_quantize_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around DEQUANTIZE->PRELU->QUANTIZE chains.

    Target pattern:
      Xq --Transpose(P)--> Aq --DEQUANTIZE--> A --PRELU(alpha)--> B --QUANTIZE--> Bq --Transpose(inv(P))--> Yq

    Rewritten:
      Xq --DEQUANTIZE--> A --PRELU(alpha')--> B --QUANTIZE--> Yq

    Safety conditions:
    - Chain is linear (single consumer at each bridge tensor)
    - Pre/Post transpose permutations are exact inverses
    - Quantized tensors use per-tensor quantization only
    - PRELU alpha tensor is constant if rank remap is required
    """
    removed_prelu_bridges = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue

            bridge_q_in = str(pre_op.outputs[0])
            dq_users = consumers.get(bridge_q_in, [])
            if len(dq_users) != 1:
                continue
            dq_idx = int(dq_users[0])
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if str(dq_op.inputs[0]) != bridge_q_in:
                continue

            bridge_f_in = str(dq_op.outputs[0])
            prelu_users = consumers.get(bridge_f_in, [])
            if len(prelu_users) != 1:
                continue
            prelu_idx = int(prelu_users[0])
            prelu_op = model_ir.operators[prelu_idx]
            if str(prelu_op.op_type) != "PRELU" or len(prelu_op.inputs) != 2 or len(prelu_op.outputs) != 1:
                continue
            if str(prelu_op.inputs[0]) != bridge_f_in:
                continue

            bridge_f_out = str(prelu_op.outputs[0])
            q_users = consumers.get(bridge_f_out, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != bridge_f_out:
                continue

            bridge_q_out = str(q_op.outputs[0])
            post_users = consumers.get(bridge_q_out, [])
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[post_idx]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != bridge_q_out:
                continue

            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                continue

            # Keep user-visible output names stable and avoid breaking observable intermediates.
            if (
                bridge_q_in in model_ir.outputs
                or bridge_f_in in model_ir.outputs
                or bridge_f_out in model_ir.outputs
                or bridge_q_out in model_ir.outputs
            ):
                continue

            q_src_name = str(pre_op.inputs[0])
            q_dst_name = str(post_op.outputs[0])
            if q_src_name in model_ir.outputs:
                continue

            q_src_tensor = model_ir.tensors.get(q_src_name, None)
            q_mid_in_tensor = model_ir.tensors.get(bridge_q_in, None)
            q_mid_out_tensor = model_ir.tensors.get(bridge_q_out, None)
            q_dst_tensor = model_ir.tensors.get(q_dst_name, None)
            if not _all_per_tensor_quantized([q_src_tensor, q_mid_in_tensor, q_mid_out_tensor, q_dst_tensor]):
                continue

            # PRELU alpha layout follows data layout. When alpha rank matches the transposed rank,
            # remap alpha using post permutation so PRELU can run directly on non-transposed data.
            alpha_name = str(prelu_op.inputs[1])
            alpha_tensor = model_ir.tensors.get(alpha_name, None)
            if alpha_tensor is not None and isinstance(alpha_tensor.data, np.ndarray):
                alpha_data = np.asarray(alpha_tensor.data)
                if alpha_data.ndim == len(perm_post):
                    alpha_data = np.transpose(alpha_data, axes=perm_post)
                    alpha_tensor.data = alpha_data
                    alpha_tensor.shape = [int(v) for v in alpha_data.shape]
                    alpha_tensor.shape_signature = [int(v) for v in alpha_data.shape]

            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_op,
                new_inputs=[q_src_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=q_op,
                new_outputs=[q_dst_name],
            )

            # Update bridge tensor metadata to the non-transposed layout.
            q_src_shape = list(q_src_tensor.shape) if q_src_tensor is not None else None
            q_src_signature = (
                list(q_src_tensor.shape_signature)
                if q_src_tensor is not None and q_src_tensor.shape_signature is not None
                else q_src_shape
            )
            if q_src_shape is not None:
                dq_out_tensor = model_ir.tensors.get(bridge_f_in, None)
                prelu_out_tensor = model_ir.tensors.get(bridge_f_out, None)
                if dq_out_tensor is not None:
                    dq_out_tensor.shape = [int(v) for v in q_src_shape]
                    dq_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if prelu_out_tensor is not None:
                    prelu_out_tensor.shape = [int(v) for v in q_src_shape]
                    prelu_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )

            if q_dst_tensor is not None and q_mid_out_tensor is not None:
                q_dst_tensor.dtype = str(q_mid_out_tensor.dtype)
                q_dst_tensor.quantization = _clone_quantization(q_mid_out_tensor.quantization)

            for remove_idx in sorted([pre_idx, post_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_prelu_bridges += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_transpose_dequant_prelu_quantize_bridges": int(removed_prelu_bridges),
    }


def _optimize_transpose_dequant_relu_quantize_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around DEQUANTIZE->(RELU|RELU6)->QUANTIZE chains.

    Target pattern:
      Xq --Transpose(P)--> Aq --DEQUANTIZE--> A --(RELU|RELU6)--> B --QUANTIZE--> Bq --Transpose(inv(P))--> Yq

    Rewritten:
      Xq --DEQUANTIZE--> A --(RELU|RELU6)--> B --QUANTIZE--> Yq

    Safety conditions:
    - Chain is linear (single consumer at each bridge tensor)
    - Pre/Post transpose permutations are exact inverses
    - Quantized tensors use per-tensor quantization only
    """
    removed_relu_bridges = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue

            bridge_q_in = str(pre_op.outputs[0])
            dq_users = consumers.get(bridge_q_in, [])
            if len(dq_users) != 1:
                continue
            dq_idx = int(dq_users[0])
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if str(dq_op.inputs[0]) != bridge_q_in:
                continue

            bridge_f_in = str(dq_op.outputs[0])
            relu_users = consumers.get(bridge_f_in, [])
            if len(relu_users) != 1:
                continue
            relu_idx = int(relu_users[0])
            relu_op = model_ir.operators[relu_idx]
            if str(relu_op.op_type) not in {"RELU", "RELU6"} or len(relu_op.inputs) != 1 or len(relu_op.outputs) != 1:
                continue
            if str(relu_op.inputs[0]) != bridge_f_in:
                continue

            bridge_f_out = str(relu_op.outputs[0])
            q_users = consumers.get(bridge_f_out, [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != bridge_f_out:
                continue

            bridge_q_out = str(q_op.outputs[0])
            post_users = consumers.get(bridge_q_out, [])
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[post_idx]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != bridge_q_out:
                continue

            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                continue

            # Keep user-visible output names stable and avoid breaking observable intermediates.
            if (
                bridge_q_in in model_ir.outputs
                or bridge_f_in in model_ir.outputs
                or bridge_f_out in model_ir.outputs
                or bridge_q_out in model_ir.outputs
            ):
                continue

            q_src_name = str(pre_op.inputs[0])
            q_dst_name = str(post_op.outputs[0])
            if q_src_name in model_ir.outputs:
                continue

            q_src_tensor = model_ir.tensors.get(q_src_name, None)
            q_mid_in_tensor = model_ir.tensors.get(bridge_q_in, None)
            q_mid_out_tensor = model_ir.tensors.get(bridge_q_out, None)
            q_dst_tensor = model_ir.tensors.get(q_dst_name, None)
            if not _all_per_tensor_quantized([q_src_tensor, q_mid_in_tensor, q_mid_out_tensor, q_dst_tensor]):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_op,
                new_inputs=[q_src_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=q_op,
                new_outputs=[q_dst_name],
            )

            # Update bridge tensor metadata to the non-transposed layout.
            q_src_shape = list(q_src_tensor.shape) if q_src_tensor is not None else None
            q_src_signature = (
                list(q_src_tensor.shape_signature)
                if q_src_tensor is not None and q_src_tensor.shape_signature is not None
                else q_src_shape
            )
            if q_src_shape is not None:
                dq_out_tensor = model_ir.tensors.get(bridge_f_in, None)
                relu_out_tensor = model_ir.tensors.get(bridge_f_out, None)
                if dq_out_tensor is not None:
                    dq_out_tensor.shape = [int(v) for v in q_src_shape]
                    dq_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if relu_out_tensor is not None:
                    relu_out_tensor.shape = [int(v) for v in q_src_shape]
                    relu_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )

            if q_dst_tensor is not None and q_mid_out_tensor is not None:
                q_dst_tensor.dtype = str(q_mid_out_tensor.dtype)
                q_dst_tensor.quantization = _clone_quantization(q_mid_out_tensor.quantization)

            for remove_idx in sorted([pre_idx, post_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_relu_bridges += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_transpose_dequant_relu_quantize_bridges": int(removed_relu_bridges),
    }


def _optimize_transpose_dequant_hardsigmoid_quantize_bridges(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around DEQUANTIZE->HardSigmoid(expanded)->QUANTIZE chains.

    Target pattern:
      Xq --Transpose(P)--> Aq --DEQUANTIZE--> A
         --MUL(c1)--> B --ADD(c2)--> C --(RELU_0_TO_1 | MAXIMUM(c3)->MINIMUM(c4))--> D
         --QUANTIZE--> Dq --Transpose(inv(P))--> Yq

    Rewritten:
      Xq --DEQUANTIZE--> A --MUL(c1')--> B --ADD(c2')--> C --(RELU_0_TO_1 | MAXIMUM(c3')->MINIMUM(c4'))--> D
         --QUANTIZE--> Yq

    Safety conditions:
    - Chain is linear (single consumer at each bridge tensor)
    - Pre/Post transpose permutations are exact inverses
    - Quantized tensors use per-tensor quantization only
    - Side inputs are constants; rank-matched constants are layout-remapped
    """
    removed_hardsigmoid_bridges = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue

            bridge_q_in = str(pre_op.outputs[0])
            dq_users = consumers.get(bridge_q_in, [])
            if len(dq_users) != 1:
                continue
            dq_idx = int(dq_users[0])
            dq_op = model_ir.operators[dq_idx]
            if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
                continue
            if str(dq_op.inputs[0]) != bridge_q_in:
                continue

            bridge_f_in = str(dq_op.outputs[0])
            mul_users = consumers.get(bridge_f_in, [])
            if len(mul_users) != 1:
                continue
            mul_idx = int(mul_users[0])
            mul_op = model_ir.operators[mul_idx]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_in0 = str(mul_op.inputs[0])
            mul_in1 = str(mul_op.inputs[1])
            if mul_in0 == bridge_f_in:
                mul_const_input_index = 1
            elif mul_in1 == bridge_f_in:
                mul_const_input_index = 0
            else:
                continue

            bridge_mul_out = str(mul_op.outputs[0])
            add_users = consumers.get(bridge_mul_out, [])
            if len(add_users) != 1:
                continue
            add_idx = int(add_users[0])
            add_op = model_ir.operators[add_idx]
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue
            add_in0 = str(add_op.inputs[0])
            add_in1 = str(add_op.inputs[1])
            if add_in0 == bridge_mul_out:
                add_const_input_index = 1
            elif add_in1 == bridge_mul_out:
                add_const_input_index = 0
            else:
                continue

            bridge_add_out = str(add_op.outputs[0])
            hs_users = consumers.get(bridge_add_out, [])
            if len(hs_users) != 1:
                continue

            hs_terminal_idx: Optional[int] = None
            hs_terminal_op: Optional[OperatorIR] = None
            bridge_hs_out: Optional[str] = None
            const_inputs_to_remap: List[Tuple[int, OperatorIR, int]] = [
                (int(mul_idx), mul_op, int(mul_const_input_index)),
                (int(add_idx), add_op, int(add_const_input_index)),
            ]
            hs_intermediate_names: List[str] = [bridge_mul_out, bridge_add_out]

            hs_candidate_idx = int(hs_users[0])
            hs_candidate_op = model_ir.operators[hs_candidate_idx]
            if (
                str(hs_candidate_op.op_type) == "RELU_0_TO_1"
                and len(hs_candidate_op.inputs) == 1
                and len(hs_candidate_op.outputs) == 1
                and str(hs_candidate_op.inputs[0]) == bridge_add_out
            ):
                hs_terminal_idx = int(hs_candidate_idx)
                hs_terminal_op = hs_candidate_op
                bridge_hs_out = str(hs_candidate_op.outputs[0])
            elif (
                str(hs_candidate_op.op_type) == "MAXIMUM"
                and len(hs_candidate_op.inputs) == 2
                and len(hs_candidate_op.outputs) == 1
            ):
                max_inputs = [str(v) for v in list(hs_candidate_op.inputs)]
                if max_inputs[0] == bridge_add_out:
                    max_const_input_index = 1
                elif max_inputs[1] == bridge_add_out:
                    max_const_input_index = 0
                else:
                    continue
                max_out_name = str(hs_candidate_op.outputs[0])
                min_users = consumers.get(max_out_name, [])
                if len(min_users) != 1:
                    continue
                min_idx = int(min_users[0])
                min_op = model_ir.operators[min_idx]
                if str(min_op.op_type) != "MINIMUM" or len(min_op.inputs) != 2 or len(min_op.outputs) != 1:
                    continue
                min_inputs = [str(v) for v in list(min_op.inputs)]
                if min_inputs[0] == max_out_name:
                    min_const_input_index = 1
                elif min_inputs[1] == max_out_name:
                    min_const_input_index = 0
                else:
                    continue
                hs_terminal_idx = int(min_idx)
                hs_terminal_op = min_op
                bridge_hs_out = str(min_op.outputs[0])
                hs_intermediate_names.append(max_out_name)
                const_inputs_to_remap.extend(
                    [
                        (int(hs_candidate_idx), hs_candidate_op, int(max_const_input_index)),
                        (int(min_idx), min_op, int(min_const_input_index)),
                    ]
                )
            else:
                continue

            if hs_terminal_idx is None or hs_terminal_op is None or bridge_hs_out is None:
                continue

            q_users = consumers.get(str(bridge_hs_out), [])
            if len(q_users) != 1:
                continue
            q_idx = int(q_users[0])
            q_op = model_ir.operators[q_idx]
            if str(q_op.op_type) != "QUANTIZE" or len(q_op.inputs) != 1 or len(q_op.outputs) != 1:
                continue
            if str(q_op.inputs[0]) != str(bridge_hs_out):
                continue

            bridge_q_out = str(q_op.outputs[0])
            post_users = consumers.get(bridge_q_out, [])
            if len(post_users) != 1:
                continue
            post_idx = int(post_users[0])
            post_op = model_ir.operators[post_idx]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if str(post_op.inputs[0]) != bridge_q_out:
                continue

            perm_post = _read_transpose_perm(model_ir, post_op)
            if perm_post is None or not _is_inverse_perm(perm_pre, perm_post):
                continue

            # Keep user-visible output names stable and avoid breaking observable intermediates.
            if (
                bridge_q_in in model_ir.outputs
                or bridge_f_in in model_ir.outputs
                or bridge_mul_out in model_ir.outputs
                or bridge_add_out in model_ir.outputs
                or str(bridge_hs_out) in model_ir.outputs
                or bridge_q_out in model_ir.outputs
            ):
                continue

            q_src_name = str(pre_op.inputs[0])
            q_dst_name = str(post_op.outputs[0])
            if q_src_name in model_ir.outputs:
                continue

            q_src_tensor = model_ir.tensors.get(q_src_name, None)
            q_mid_in_tensor = model_ir.tensors.get(bridge_q_in, None)
            q_mid_out_tensor = model_ir.tensors.get(bridge_q_out, None)
            q_dst_tensor = model_ir.tensors.get(q_dst_name, None)
            if not _all_per_tensor_quantized([q_src_tensor, q_mid_in_tensor, q_mid_out_tensor, q_dst_tensor]):
                continue

            def _remap_constant_input_for_op(
                *,
                op: OperatorIR,
                op_idx: int,
                input_index: int,
            ) -> bool:
                const_name = str(op.inputs[input_index])
                const_tensor = model_ir.tensors.get(const_name, None)
                if const_tensor is None or const_tensor.data is None:
                    return False
                const_data = np.asarray(const_tensor.data)
                if const_data.ndim != len(perm_post):
                    return True
                transposed_data = np.transpose(const_data, axes=perm_post)
                const_users = consumers.get(const_name, [])
                if len(const_users) == 1 and int(const_users[0]) == int(op_idx):
                    const_tensor.data = np.asarray(transposed_data)
                    const_tensor.shape = [int(v) for v in transposed_data.shape]
                    const_tensor.shape_signature = [int(v) for v in transposed_data.shape]
                    return True
                new_name = _unique_tensor_name(f"{const_name}_nhwc")
                model_ir.tensors[new_name] = TensorIR(
                    name=new_name,
                    dtype=str(const_tensor.dtype),
                    shape=[int(v) for v in transposed_data.shape],
                    shape_signature=[int(v) for v in transposed_data.shape],
                    data=np.asarray(transposed_data),
                    is_variable=False,
                    quantization=_clone_quantization(const_tensor.quantization),
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=op,
                    input_index=int(input_index),
                    new_input_name=str(new_name),
                )
                return True

            remap_ok = True
            for remap_idx, remap_op, remap_input_index in const_inputs_to_remap:
                if not _remap_constant_input_for_op(
                    op=remap_op,
                    op_idx=int(remap_idx),
                    input_index=int(remap_input_index),
                ):
                    remap_ok = False
                    break
            if not remap_ok:
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=dq_op,
                new_inputs=[q_src_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=q_op,
                new_outputs=[q_dst_name],
            )

            # Update bridge tensor metadata to the non-transposed layout.
            q_src_shape = list(q_src_tensor.shape) if q_src_tensor is not None else None
            q_src_signature = (
                list(q_src_tensor.shape_signature)
                if q_src_tensor is not None and q_src_tensor.shape_signature is not None
                else q_src_shape
            )
            if q_src_shape is not None:
                dq_out_tensor = model_ir.tensors.get(bridge_f_in, None)
                mul_out_tensor = model_ir.tensors.get(bridge_mul_out, None)
                add_out_tensor = model_ir.tensors.get(bridge_add_out, None)
                hs_out_tensor = model_ir.tensors.get(str(bridge_hs_out), None)
                if dq_out_tensor is not None:
                    dq_out_tensor.shape = [int(v) for v in q_src_shape]
                    dq_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if mul_out_tensor is not None:
                    mul_out_tensor.shape = [int(v) for v in q_src_shape]
                    mul_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if add_out_tensor is not None:
                    add_out_tensor.shape = [int(v) for v in q_src_shape]
                    add_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                for hs_intermediate_name in hs_intermediate_names:
                    hs_mid_tensor = model_ir.tensors.get(str(hs_intermediate_name), None)
                    if hs_mid_tensor is None:
                        continue
                    hs_mid_tensor.shape = [int(v) for v in q_src_shape]
                    hs_mid_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )
                if hs_out_tensor is not None:
                    hs_out_tensor.shape = [int(v) for v in q_src_shape]
                    hs_out_tensor.shape_signature = (
                        [int(v) for v in q_src_signature]
                        if q_src_signature is not None
                        else [int(v) for v in q_src_shape]
                    )

            if q_dst_tensor is not None and q_mid_out_tensor is not None:
                q_dst_tensor.dtype = str(q_mid_out_tensor.dtype)
                q_dst_tensor.quantization = _clone_quantization(q_mid_out_tensor.quantization)

            for remove_idx in sorted([pre_idx, post_idx], reverse=True):
                del model_ir.operators[remove_idx]
            removed_hardsigmoid_bridges += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "removed_transpose_dequant_hardsigmoid_quantize_bridges": int(removed_hardsigmoid_bridges),
    }


